/**
 * Shared domain types for the Weekly Commit Module.
 * Consumed by the frontend micro-frontend and monorepo tooling.
 */

export * from "./enums.js";
export * from "./constants.js";
export type * from "./types.js";
export * from "./validators.js";

import {
  VALID_ESTIMATE_POINTS,
  MAX_KING_PER_WEEK,
  MAX_QUEEN_PER_WEEK,
  SOFT_MAX_COMMITS,
  PAWN_POINT_WARNING_THRESHOLD,
} from "./constants.js";
import type { EstimatePoints } from "./constants.js";
import { ChessPiece } from "./enums.js";

/**
 * Returns true when `points` is a valid Fibonacci estimate value
 * (1, 2, 3, 5, or 8).
 */
export function isValidEstimate(points: number): points is EstimatePoints {
  return (VALID_ESTIMATE_POINTS as readonly number[]).includes(points);
}

/**
 * Returns true when adding `piece` to the week does not violate the
 * hard guardrails:
 * - KING: max 1 per week
 * - QUEEN: max 2 per week
 * - All others: unlimited
 */
export function isChessPieceWithinLimit(
  piece: ChessPiece,
  existingPieces: readonly ChessPiece[],
): boolean {
  if (piece === ChessPiece.KING) {
    const kingCount = existingPieces.filter((p) => p === ChessPiece.KING)
      .length;
    return kingCount < MAX_KING_PER_WEEK;
  }
  if (piece === ChessPiece.QUEEN) {
    const queenCount = existingPieces.filter((p) => p === ChessPiece.QUEEN)
      .length;
    return queenCount < MAX_QUEEN_PER_WEEK;
  }
  return true;
}

/**
 * Returns true when the commit count exceeds the soft maximum.
 * Used to trigger a UI warning, not a hard block.
 */
export function isOverSoftCommitLimit(commitCount: number): boolean {
  return commitCount > SOFT_MAX_COMMITS;
}

/**
 * Returns true when Pawn-piece points represent more than the warning
 * threshold fraction of total planned points.
 */
export function isPawnHeavy(pawnPoints: number, totalPoints: number): boolean {
  if (totalPoints === 0) {
    return false;
  }
  return pawnPoints / totalPoints > PAWN_POINT_WARNING_THRESHOLD;
}

import { describe, expect, it } from "vitest";
import { ChessPiece } from "./enums.js";
import {
  isChessPieceWithinLimit,
  isOverSoftCommitLimit,
  isPawnHeavy,
  isValidEstimate,
} from "./validators.js";

describe("isValidEstimate", () => {
  it("accepts each valid Fibonacci point value", () => {
    expect(isValidEstimate(1)).toBe(true);
    expect(isValidEstimate(2)).toBe(true);
    expect(isValidEstimate(3)).toBe(true);
    expect(isValidEstimate(5)).toBe(true);
    expect(isValidEstimate(8)).toBe(true);
  });

  it("rejects non-Fibonacci values", () => {
    expect(isValidEstimate(0)).toBe(false);
    expect(isValidEstimate(4)).toBe(false);
    expect(isValidEstimate(6)).toBe(false);
    expect(isValidEstimate(7)).toBe(false);
    expect(isValidEstimate(10)).toBe(false);
  });

  it("rejects negative values", () => {
    expect(isValidEstimate(-1)).toBe(false);
  });
});

describe("isChessPieceWithinLimit", () => {
  it("allows King when no Kings exist", () => {
    expect(isChessPieceWithinLimit(ChessPiece.KING, [])).toBe(true);
  });

  it("blocks a second King commit", () => {
    expect(
      isChessPieceWithinLimit(ChessPiece.KING, [ChessPiece.KING]),
    ).toBe(false);
  });

  it("allows first Queen", () => {
    expect(isChessPieceWithinLimit(ChessPiece.QUEEN, [])).toBe(true);
  });

  it("allows second Queen", () => {
    expect(
      isChessPieceWithinLimit(ChessPiece.QUEEN, [ChessPiece.QUEEN]),
    ).toBe(true);
  });

  it("blocks a third Queen commit", () => {
    expect(
      isChessPieceWithinLimit(ChessPiece.QUEEN, [
        ChessPiece.QUEEN,
        ChessPiece.QUEEN,
      ]),
    ).toBe(false);
  });

  it("places no cap on Rook commits", () => {
    const tenRooks: ChessPiece[] = Array.from(
      { length: 10 },
      () => ChessPiece.ROOK,
    );
    expect(isChessPieceWithinLimit(ChessPiece.ROOK, tenRooks)).toBe(true);
  });

  it("places no cap on Pawn commits", () => {
    expect(
      isChessPieceWithinLimit(ChessPiece.PAWN, [
        ChessPiece.PAWN,
        ChessPiece.PAWN,
        ChessPiece.PAWN,
      ]),
    ).toBe(true);
  });
});

describe("isOverSoftCommitLimit", () => {
  it("returns false at or below 8 commits", () => {
    expect(isOverSoftCommitLimit(0)).toBe(false);
    expect(isOverSoftCommitLimit(8)).toBe(false);
  });

  it("returns true above 8 commits", () => {
    expect(isOverSoftCommitLimit(9)).toBe(true);
    expect(isOverSoftCommitLimit(20)).toBe(true);
  });
});

describe("isPawnHeavy", () => {
  it("returns false when total points is zero", () => {
    expect(isPawnHeavy(0, 0)).toBe(false);
  });

  it("returns false when Pawn fraction is at or below the threshold", () => {
    // 4/10 = 0.4, which is exactly the threshold — should NOT warn
    expect(isPawnHeavy(4, 10)).toBe(false);
  });

  it("returns true when Pawn fraction exceeds the threshold", () => {
    // 5/10 = 0.5 > 0.4
    expect(isPawnHeavy(5, 10)).toBe(true);
  });
});

/** Weekly plan lifecycle state. */
export enum PlanState {
  DRAFT = "DRAFT",
  LOCKED = "LOCKED",
  RECONCILING = "RECONCILING",
  RECONCILED = "RECONCILED",
}

/** Chess-piece taxonomy for commit prioritization. */
export enum ChessPiece {
  KING = "KING",
  QUEEN = "QUEEN",
  ROOK = "ROOK",
  BISHOP = "BISHOP",
  KNIGHT = "KNIGHT",
  PAWN = "PAWN",
}

/** Outcome recorded at reconciliation time. */
export enum CommitOutcome {
  ACHIEVED = "ACHIEVED",
  PARTIALLY_ACHIEVED = "PARTIALLY_ACHIEVED",
  NOT_ACHIEVED = "NOT_ACHIEVED",
  CANCELED = "CANCELED",
}

/** Level in the RCDO strategy hierarchy. */
export enum RcdoNodeType {
  RALLY_CRY = "RALLY_CRY",
  DEFINING_OBJECTIVE = "DEFINING_OBJECTIVE",
  OUTCOME = "OUTCOME",
}

/** Lifecycle status of an RCDO node. */
export enum RcdoNodeStatus {
  DRAFT = "DRAFT",
  ACTIVE = "ACTIVE",
  ARCHIVED = "ARCHIVED",
}

/** Native work-item (ticket) workflow statuses. */
export enum TicketStatus {
  BACKLOG = "BACKLOG",
  READY = "READY",
  IN_PROGRESS = "IN_PROGRESS",
  BLOCKED = "BLOCKED",
  DONE = "DONE",
  CANCELED = "CANCELED",
}

/** Categories for post-lock scope change events. */
export enum ScopeChangeCategory {
  COMMIT_ADDED = "COMMIT_ADDED",
  COMMIT_REMOVED = "COMMIT_REMOVED",
  ESTIMATE_CHANGED = "ESTIMATE_CHANGED",
  CHESS_PIECE_CHANGED = "CHESS_PIECE_CHANGED",
  RCDO_CHANGED = "RCDO_CHANGED",
  PRIORITY_CHANGED = "PRIORITY_CHANGED",
}

/** Controlled reason list for explicit carry-forward. */
export enum CarryForwardReason {
  BLOCKED_BY_DEPENDENCY = "BLOCKED_BY_DEPENDENCY",
  SCOPE_EXPANDED = "SCOPE_EXPANDED",
  REPRIORITIZED = "REPRIORITIZED",
  RESOURCE_UNAVAILABLE = "RESOURCE_UNAVAILABLE",
  TECHNICAL_OBSTACLE = "TECHNICAL_OBSTACLE",
  EXTERNAL_DELAY = "EXTERNAL_DELAY",
  UNDERESTIMATED = "UNDERESTIMATED",
  STILL_IN_PROGRESS = "STILL_IN_PROGRESS",
}

/** Valid Fibonacci-scale estimate point values. */
export const VALID_ESTIMATE_POINTS = [1, 2, 3, 5, 8] as const;

/** Union type of valid estimate point values. */
export type EstimatePoints = (typeof VALID_ESTIMATE_POINTS)[number];

/** Default weekly capacity budget for a full-time user (points). */
export const DEFAULT_WEEKLY_BUDGET = 10 as const;

/** Maximum King-piece commits allowed per user per week. */
export const MAX_KING_PER_WEEK = 1 as const;

/** Maximum Queen-piece commits allowed per user per week. */
export const MAX_QUEEN_PER_WEEK = 2 as const;

/** Soft warning threshold for total active commit count. */
export const SOFT_MAX_COMMITS = 8 as const;

/**
 * If Pawn-piece points represent more than this fraction of total planned
 * points, show a distribution warning.
 */
export const PAWN_POINT_WARNING_THRESHOLD = 0.4 as const;

import type {
  CarryForwardReason,
  ChessPiece,
  CommitOutcome,
  PlanState,
  RcdoNodeStatus,
  RcdoNodeType,
  ScopeChangeCategory,
  TicketStatus,
} from "./enums.js";
import type { EstimatePoints } from "./constants.js";

/** One plan per user per week; the top-level weekly planning object. */
export interface WeeklyPlan {
  readonly id: string;
  readonly ownerUserId: string;
  readonly teamId: string;
  /** ISO date: yyyy-MM-dd (Monday). */
  readonly weekStartDate: string;
  state: PlanState;
  /** ISO datetime for manual-lock deadline. */
  readonly lockDeadline: string;
  /** ISO datetime for reconciliation deadline. */
  readonly reconcileDeadline: string;
  capacityBudgetPoints: number;
  isCompliant: boolean;
  systemLockedWithErrors: boolean;
  lockSnapshotId?: string;
  reconcileSnapshotId?: string;
  readonly createdAt: string;
  updatedAt: string;
}

/** A single weekly work commitment inside a plan. */
export interface Commit {
  readonly id: string;
  readonly planId: string;
  readonly ownerUserId: string;
  title: string;
  description?: string;
  chessPiece: ChessPiece;
  priorityOrder: number;
  /** Required at lock; the primary RCDO node linked. */
  rcdoNodeId?: string;
  ticketId?: string;
  /** Required at lock; Fibonacci point estimate. */
  estimatePoints?: EstimatePoints;
  /** Required for KING and QUEEN chess pieces. */
  successCriteria?: string;
  outcome?: CommitOutcome;
  outcomeNotes?: string;
  carryForwardSourceId?: string;
  carryForwardStreak: number;
  readonly createdAt: string;
  updatedAt: string;
}

/** A node in the Rally Cry → Defining Objective → Outcome hierarchy. */
export interface RcdoNode {
  readonly id: string;
  nodeType: RcdoNodeType;
  status: RcdoNodeStatus;
  parentId?: string;
  title: string;
  description?: string;
  ownerTeamId?: string;
  ownerUserId?: string;
  readonly createdAt: string;
  updatedAt: string;
}

/** A durable native work item (ticket) that may span multiple weeks. */
export interface Ticket {
  readonly id: string;
  readonly key: string;
  title: string;
  description?: string;
  status: TicketStatus;
  assigneeUserId?: string;
  readonly reporterUserId: string;
  readonly teamId: string;
  estimatePoints?: EstimatePoints;
  rcdoNodeId?: string;
  /** ISO date: yyyy-MM-dd of the target week Monday. */
  targetWeekStartDate?: string;
  readonly createdAt: string;
  updatedAt: string;
}

/** Immutable baseline snapshot captured at plan lock time. */
export interface LockSnapshot {
  readonly id: string;
  readonly planId: string;
  readonly lockedAt: string;
  readonly lockedBySystem: boolean;
  /** Denormalized JSON payload for historical replay. */
  readonly snapshotPayload: string;
}

/** A structured event recording a change made after plan lock. */
export interface ScopeChangeEvent {
  readonly id: string;
  readonly planId: string;
  commitId?: string;
  readonly category: ScopeChangeCategory;
  readonly changedByUserId: string;
  readonly reason: string;
  previousValue?: string;
  newValue?: string;
  readonly createdAt: string;
}

/** Immutable actual snapshot captured at reconciliation time. */
export interface ReconcileSnapshot {
  readonly id: string;
  readonly planId: string;
  readonly reconciledAt: string;
  /** Denormalized JSON payload for historical replay. */
  readonly snapshotPayload: string;
}

/** Provenance link from a source commit to its carry-forward target. */
export interface CarryForwardLink {
  readonly id: string;
  readonly sourceCommitId: string;
  readonly targetCommitId: string;
  readonly reason: CarryForwardReason;
  reasonNotes?: string;
  readonly createdAt: string;
}

/** A stored AI suggestion with mandatory rationale and audit metadata. */
export interface AiSuggestion {
  readonly id: string;
  planId?: string;
  commitId?: string;
  readonly suggestionType: string;
  readonly prompt: string;
  readonly rationale: string;
  readonly suggestionPayload: string;
  readonly modelVersion: string;
  accepted?: boolean;
  dismissed?: boolean;
  readonly createdAt: string;
}

/** Manager comment on a plan or commit. */
export interface ManagerComment {
  readonly id: string;
  planId?: string;
  commitId?: string;
  readonly authorUserId: string;
  content: string;
  readonly createdAt: string;
  updatedAt: string;
}

/** Per-user weekly capacity override set by a manager. */
export interface CapacityOverride {
  readonly id: string;
  readonly userId: string;
  /** ISO date: yyyy-MM-dd of the target week Monday. */
  readonly weekStartDate: string;
  budgetPoints: number;
  reason?: string;
  readonly setByManagerId: string;
  readonly createdAt: string;
}

/** An in-app notification for a user. */
export interface Notification {
  readonly id: string;
  readonly recipientUserId: string;
  readonly notificationType: string;
  readonly title: string;
  readonly body: string;
  referenceId?: string;
  referenceType?: string;
  read: boolean;
  readonly createdAt: string;
}

package com.weeklycommit.domain;

import static org.assertj.core.api.Assertions.assertThat;

import com.weeklycommit.domain.entity.Organization;
import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.RcdoNodeType;
import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import java.time.Instant;
import java.time.LocalDate;
import java.util.Set;
import java.util.UUID;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class EntityValidationTest {

	private static Validator validator;

	@BeforeAll
	static void setUpValidator() {
		ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
		validator = factory.getValidator();
	}

	// -------------------------------------------------------------------------
	// Organization
	// -------------------------------------------------------------------------

	@Test
	void organization_blankNameFails() {
		Organization org = new Organization();
		org.setName("");
		Set<ConstraintViolation<Organization>> violations = validator.validate(org);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("name"));
	}

	@Test
	void organization_validNamePasses() {
		Organization org = new Organization();
		org.setName("Acme Corp");
		Set<ConstraintViolation<Organization>> violations = validator.validate(org);
		assertThat(violations).noneMatch(v -> v.getPropertyPath().toString().equals("name"));
	}

	// -------------------------------------------------------------------------
	// UserAccount
	// -------------------------------------------------------------------------

	@Test
	void userAccount_missingEmailFails() {
		UserAccount user = new UserAccount();
		user.setOrganizationId(UUID.randomUUID());
		user.setDisplayName("Alice");
		// email intentionally not set
		Set<ConstraintViolation<UserAccount>> violations = validator.validate(user);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("email"));
	}

	@Test
	void userAccount_invalidEmailFails() {
		UserAccount user = new UserAccount();
		user.setOrganizationId(UUID.randomUUID());
		user.setEmail("not-an-email");
		user.setDisplayName("Alice");
		Set<ConstraintViolation<UserAccount>> violations = validator.validate(user);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("email"));
	}

	// -------------------------------------------------------------------------
	// WeeklyPlan
	// -------------------------------------------------------------------------

	@Test
	void weeklyPlan_missingOwnerFails() {
		WeeklyPlan plan = new WeeklyPlan();
		plan.setTeamId(UUID.randomUUID());
		plan.setWeekStartDate(LocalDate.now());
		plan.setLockDeadline(Instant.now());
		plan.setReconcileDeadline(Instant.now());
		// ownerUserId intentionally not set
		Set<ConstraintViolation<WeeklyPlan>> violations = validator.validate(plan);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("ownerUserId"));
	}

	@Test
	void weeklyPlan_validMinimalPlanPasses() {
		WeeklyPlan plan = new WeeklyPlan();
		plan.setOwnerUserId(UUID.randomUUID());
		plan.setTeamId(UUID.randomUUID());
		plan.setWeekStartDate(LocalDate.now());
		plan.setLockDeadline(Instant.now());
		plan.setReconcileDeadline(Instant.now());
		Set<ConstraintViolation<WeeklyPlan>> violations = validator.validate(plan);
		assertThat(violations).isEmpty();
	}

	// -------------------------------------------------------------------------
	// WeeklyCommit
	// -------------------------------------------------------------------------

	@Test
	void weeklyCommit_blankTitleFails() {
		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(UUID.randomUUID());
		commit.setOwnerUserId(UUID.randomUUID());
		commit.setTitle("");
		commit.setChessPiece(ChessPiece.PAWN);
		commit.setPriorityOrder(1);
		Set<ConstraintViolation<WeeklyCommit>> violations = validator.validate(commit);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("title"));
	}

	@Test
	void weeklyCommit_missingChessPieceFails() {
		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(UUID.randomUUID());
		commit.setOwnerUserId(UUID.randomUUID());
		commit.setTitle("Ship the feature");
		commit.setPriorityOrder(1);
		// chessPiece intentionally not set
		Set<ConstraintViolation<WeeklyCommit>> violations = validator.validate(commit);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("chessPiece"));
	}

	@Test
	void weeklyCommit_validCommitPasses() {
		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(UUID.randomUUID());
		commit.setOwnerUserId(UUID.randomUUID());
		commit.setTitle("Ship the feature");
		commit.setChessPiece(ChessPiece.ROOK);
		commit.setPriorityOrder(1);
		Set<ConstraintViolation<WeeklyCommit>> violations = validator.validate(commit);
		assertThat(violations).isEmpty();
	}

	// -------------------------------------------------------------------------
	// RcdoNode
	// -------------------------------------------------------------------------

	@Test
	void rcdoNode_blankTitleFails() {
		RcdoNode node = new RcdoNode();
		node.setNodeType(RcdoNodeType.OUTCOME);
		node.setTitle("");
		Set<ConstraintViolation<RcdoNode>> violations = validator.validate(node);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("title"));
	}

	@Test
	void rcdoNode_missingNodeTypeFails() {
		RcdoNode node = new RcdoNode();
		node.setTitle("Grow revenue");
		// nodeType intentionally not set
		Set<ConstraintViolation<RcdoNode>> violations = validator.validate(node);
		assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("nodeType"));
	}

	@Test
	void rcdoNode_validNodePasses() {
		RcdoNode node = new RcdoNode();
		node.setNodeType(RcdoNodeType.OUTCOME);
		node.setTitle("Grow revenue by 20%");
		Set<ConstraintViolation<RcdoNode>> violations = validator.validate(node);
		assertThat(violations).isEmpty();
	}
}

