package com.weeklycommit.reconcile.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.domain.entity.LockSnapshotHeader;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.CommitOutcome;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.enums.ScopeChangeCategory;
import com.weeklycommit.domain.repository.LockSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.reconcile.dto.AddCommitData;
import com.weeklycommit.reconcile.dto.EditCommitChanges;
import com.weeklycommit.reconcile.dto.ManagerException;
import com.weeklycommit.reconcile.dto.ScopeChangeEventResponse;
import com.weeklycommit.reconcile.dto.ScopeChangeTimelineResponse;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles post-lock scope changes on a LOCKED plan. All commit mutations after
 * lock are routed through this service so every change is recorded as an
 * immutable {@link ScopeChangeEvent} with before/after values.
 */
@Service
@Transactional
public class ScopeChangeService {

	/** King-related change threshold that triggers a manager exception. */
	private static final ChessPiece KING = ChessPiece.KING;

	/**
	 * Percent increase in total estimate points that triggers a manager exception.
	 */
	private static final double POINTS_INCREASE_THRESHOLD_PCT = 0.20;

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ScopeChangeEventRepository eventRepo;
	private final LockSnapshotHeaderRepository lockSnapshotRepo;
	private final ObjectMapper objectMapper;

	public ScopeChangeService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			ScopeChangeEventRepository eventRepo, LockSnapshotHeaderRepository lockSnapshotRepo,
			ObjectMapper objectMapper) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.eventRepo = eventRepo;
		this.lockSnapshotRepo = lockSnapshotRepo;
		this.objectMapper = objectMapper;
	}

	// -------------------------------------------------------------------------
	// Add post-lock commit
	// -------------------------------------------------------------------------

	/**
	 * Adds a new commit to a LOCKED plan and records a COMMIT_ADDED scope-change
	 * event.
	 *
	 * @return updated change timeline including the new event
	 */
	public ScopeChangeTimelineResponse addPostLockCommit(UUID planId, AddCommitData data, String reason,
			UUID actorUserId) {
		validateReason(reason);
		WeeklyPlan plan = requireLockedPlan(planId);

		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(planId);
		commit.setOwnerUserId(plan.getOwnerUserId());
		commit.setTitle(data.title());
		commit.setChessPiece(data.chessPiece());
		commit.setDescription(data.description());
		commit.setRcdoNodeId(data.rcdoNodeId());
		commit.setWorkItemId(data.workItemId());
		commit.setEstimatePoints(data.estimatePoints());
		commit.setSuccessCriteria(data.successCriteria());
		commit.setPriorityOrder(nextPriorityOrder(planId));
		WeeklyCommit saved = commitRepo.save(commit);

		ScopeChangeEvent event = newEvent(planId, saved.getId(), ScopeChangeCategory.COMMIT_ADDED, actorUserId, reason);
		event.setPreviousValue(null);
		event.setNewValue(toJson(commitToMap(saved)));
		eventRepo.save(event);

		return getChangeTimeline(planId);
	}

	// -------------------------------------------------------------------------
	// Remove post-lock commit
	// -------------------------------------------------------------------------

	/**
	 * Marks an existing commit on a LOCKED plan as canceled and records a
	 * COMMIT_REMOVED scope-change event.
	 *
	 * @return updated change timeline
	 */
	public ScopeChangeTimelineResponse removePostLockCommit(UUID commitId, String reason, UUID actorUserId) {
		validateReason(reason);
		WeeklyCommit commit = requireCommit(commitId);
		requireLockedPlan(commit.getPlanId());

		commit.setOutcome(CommitOutcome.CANCELED);
		commit.setOutcomeNotes(reason);
		commitRepo.save(commit);

		ScopeChangeEvent event = newEvent(commit.getPlanId(), commitId, ScopeChangeCategory.COMMIT_REMOVED, actorUserId,
				reason);
		event.setPreviousValue(toJson(java.util.Map.of("outcome", "null")));
		event.setNewValue(toJson(java.util.Map.of("outcome", CommitOutcome.CANCELED.name())));
		eventRepo.save(event);

		return getChangeTimeline(commit.getPlanId());
	}

	// -------------------------------------------------------------------------
	// Edit post-lock commit
	// -------------------------------------------------------------------------

	/**
	 * Applies mutable-field changes to a commit on a LOCKED plan. A separate
	 * SCOPE_CHANGE event is created for each changed field.
	 *
	 * @return updated change timeline
	 */
	public ScopeChangeTimelineResponse editPostLockCommit(UUID commitId, EditCommitChanges changes, String reason,
			UUID actorUserId) {
		validateReason(reason);
		WeeklyCommit commit = requireCommit(commitId);
		requireLockedPlan(commit.getPlanId());

		if (changes.estimatePoints() != null && !changes.estimatePoints().equals(commit.getEstimatePoints())) {
			recordFieldChange(commit, ScopeChangeCategory.ESTIMATE_CHANGED, actorUserId, reason,
					str(commit.getEstimatePoints()), str(changes.estimatePoints()));
			commit.setEstimatePoints(changes.estimatePoints());
		}

		if (changes.chessPiece() != null && changes.chessPiece() != commit.getChessPiece()) {
			recordFieldChange(commit, ScopeChangeCategory.CHESS_PIECE_CHANGED, actorUserId, reason,
					str(commit.getChessPiece()), str(changes.chessPiece()));
			commit.setChessPiece(changes.chessPiece());
		}

		if (changes.rcdoNodeId() != null && !changes.rcdoNodeId().equals(commit.getRcdoNodeId())) {
			recordFieldChange(commit, ScopeChangeCategory.RCDO_CHANGED, actorUserId, reason,
					str(commit.getRcdoNodeId()), str(changes.rcdoNodeId()));
			commit.setRcdoNodeId(changes.rcdoNodeId());
		}

		if (changes.priorityOrder() != null && changes.priorityOrder() != commit.getPriorityOrder()) {
			recordFieldChange(commit, ScopeChangeCategory.PRIORITY_CHANGED, actorUserId, reason,
					str(commit.getPriorityOrder()), str(changes.priorityOrder()));
			commit.setPriorityOrder(changes.priorityOrder());
		}

		commitRepo.save(commit);

		return getChangeTimeline(commit.getPlanId());
	}

	// -------------------------------------------------------------------------
	// Change timeline
	// -------------------------------------------------------------------------

	/**
	 * Returns the full chronological scope-change timeline for a plan, together
	 * with any manager-exception flags.
	 */
	@Transactional(readOnly = true)
	public ScopeChangeTimelineResponse getChangeTimeline(UUID planId) {
		List<ScopeChangeEvent> events = eventRepo.findByPlanIdOrderByCreatedAtAsc(planId);
		List<ScopeChangeEventResponse> responses = events.stream().map(ScopeChangeEventResponse::from).toList();
		List<ManagerException> exceptions = detectManagerExceptions(planId, events);
		return new ScopeChangeTimelineResponse(responses, exceptions);
	}

	// -------------------------------------------------------------------------
	// Manager exception detection
	// -------------------------------------------------------------------------

	/**
	 * Evaluates the current scope-change events against manager-exception
	 * thresholds. Flags are re-derived from events each call (no persistent state).
	 */
	List<ManagerException> detectManagerExceptions(UUID planId, List<ScopeChangeEvent> events) {
		List<ManagerException> exceptions = new ArrayList<>();

		// Rule 1: King added or changed to/from KING
		boolean kingException = false;
		for (ScopeChangeEvent e : events) {
			if (e.getCategory() == ScopeChangeCategory.COMMIT_ADDED) {
				try {
					JsonNode node = objectMapper.readTree(e.getNewValue());
					if (KING.name().equals(node.path("chessPiece").asText(null))) {
						kingException = true;
					}
				} catch (Exception ignored) {
					// malformed JSON — skip
				}
			} else if (e.getCategory() == ScopeChangeCategory.CHESS_PIECE_CHANGED) {
				String prev = e.getPreviousValue();
				String next = e.getNewValue();
				if (KING.name().equals(prev) || KING.name().equals(next)) {
					kingException = true;
				}
			}
		}
		if (kingException) {
			exceptions.add(new ManagerException(ManagerException.TYPE_KING_CHANGE,
					"A King-level commit was added or changed post-lock"));
		}

		// Rule 2: Total estimate points increased >20% from baseline
		lockSnapshotRepo.findByPlanId(planId).ifPresent(header -> {
			int baselinePoints = parseBaselinePoints(header);
			if (baselinePoints > 0) {
				int currentPoints = commitRepo.findByPlanIdOrderByPriorityOrder(planId).stream()
						.filter(c -> c.getOutcome() != CommitOutcome.CANCELED)
						.mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum();
				double increase = (double) (currentPoints - baselinePoints) / baselinePoints;
				if (increase > POINTS_INCREASE_THRESHOLD_PCT) {
					exceptions.add(new ManagerException(ManagerException.TYPE_POINTS_INCREASE_20PCT,
							String.format("Total estimate points increased %.0f%% from baseline (%d → %d points)",
									increase * 100, baselinePoints, currentPoints)));
				}
			}
		});

		return exceptions;
	}

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan requireLockedPlan(UUID planId) {
		WeeklyPlan plan = planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
		if (plan.getState() != PlanState.LOCKED) {
			throw new PlanValidationException(
					"Scope changes are only allowed on LOCKED plans; current state: " + plan.getState());
		}
		return plan;
	}

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private static void validateReason(String reason) {
		if (reason == null || reason.isBlank()) {
			throw new PlanValidationException("A non-empty reason is required for all post-lock scope changes");
		}
	}

	private ScopeChangeEvent newEvent(UUID planId, UUID commitId, ScopeChangeCategory category, UUID actorUserId,
			String reason) {
		ScopeChangeEvent e = new ScopeChangeEvent();
		e.setPlanId(planId);
		e.setCommitId(commitId);
		e.setCategory(category);
		e.setChangedByUserId(
				actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		e.setReason(reason);
		return e;
	}

	private void recordFieldChange(WeeklyCommit commit, ScopeChangeCategory category, UUID actorUserId, String reason,
			String previousValue, String newValue) {
		ScopeChangeEvent e = newEvent(commit.getPlanId(), commit.getId(), category, actorUserId, reason);
		e.setPreviousValue(previousValue);
		e.setNewValue(newValue);
		eventRepo.save(e);
	}

	private int parseBaselinePoints(LockSnapshotHeader header) {
		try {
			JsonNode root = objectMapper.readTree(header.getSnapshotPayload());
			JsonNode commits = root.path("commits");
			if (!commits.isArray())
				return 0;
			int total = 0;
			for (JsonNode c : commits) {
				JsonNode ep = c.path("estimatePoints");
				if (!ep.isMissingNode() && !ep.isNull()) {
					total += ep.asInt(0);
				}
			}
			return total;
		} catch (JsonProcessingException e) {
			return 0;
		}
	}

	private int nextPriorityOrder(UUID planId) {
		return (int) (commitRepo.countByPlanId(planId) + 1);
	}

	private java.util.Map<String, Object> commitToMap(WeeklyCommit c) {
		java.util.Map<String, Object> m = new java.util.LinkedHashMap<>();
		m.put("id", str(c.getId()));
		m.put("title", c.getTitle());
		m.put("chessPiece", c.getChessPiece() != null ? c.getChessPiece().name() : null);
		m.put("estimatePoints", c.getEstimatePoints());
		m.put("rcdoNodeId", str(c.getRcdoNodeId()));
		m.put("priorityOrder", c.getPriorityOrder());
		return m;
	}

	private String toJson(Object o) {
		try {
			return objectMapper.writeValueAsString(o);
		} catch (JsonProcessingException e) {
			throw new IllegalStateException("JSON serialisation failed", e);
		}
	}

	private static String str(Object o) {
		return o != null ? o.toString() : null;
	}
}

package com.weeklycommit.reconcile.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.domain.entity.LockSnapshotCommit;
import com.weeklycommit.domain.entity.LockSnapshotHeader;
import com.weeklycommit.domain.entity.ReconcileSnapshotCommit;
import com.weeklycommit.domain.entity.ReconcileSnapshotHeader;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.enums.CommitOutcome;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.enums.ScopeChangeCategory;
import com.weeklycommit.domain.enums.TicketStatus;
import com.weeklycommit.domain.repository.LockSnapshotCommitRepository;
import com.weeklycommit.domain.repository.LockSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.ReconcileSnapshotCommitRepository;
import com.weeklycommit.domain.repository.ReconcileSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.reconcile.dto.ReconcileCommitView;
import com.weeklycommit.reconcile.dto.ReconciliationViewResponse;
import com.weeklycommit.reconcile.dto.ScopeChangeEventResponse;
import java.time.Instant;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import java.util.UUID;
import java.util.stream.Collectors;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Manages the RECONCILING phase of a weekly plan's lifecycle.
 *
 * <p>
 * Responsibilities:
 * <ol>
 * <li>Opening reconciliation — idempotent LOCKED → RECONCILING transition with
 * auto-achieve for linked DONE tickets.</li>
 * <li>Providing the reconciliation view — baseline vs current commit data.</li>
 * <li>Setting individual commit outcomes.</li>
 * <li>Submitting the final reconciliation — validates completeness, writes
 * immutable snapshot, and transitions to RECONCILED.</li>
 * </ol>
 */
@Service
@Transactional
public class ReconciliationService {

	/** Outcomes that require accompanying notes. */
	private static final Set<CommitOutcome> NOTES_REQUIRED_OUTCOMES = Set.of(CommitOutcome.PARTIALLY_ACHIEVED,
			CommitOutcome.NOT_ACHIEVED, CommitOutcome.CANCELED);

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final WorkItemRepository workItemRepo;
	private final ScopeChangeEventRepository eventRepo;
	private final LockSnapshotHeaderRepository lockHeaderRepo;
	private final LockSnapshotCommitRepository lockCommitRepo;
	private final ReconcileSnapshotHeaderRepository reconcileHeaderRepo;
	private final ReconcileSnapshotCommitRepository reconcileCommitRepo;
	private final ObjectMapper objectMapper;

	public ReconciliationService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			WorkItemRepository workItemRepo, ScopeChangeEventRepository eventRepo,
			LockSnapshotHeaderRepository lockHeaderRepo, LockSnapshotCommitRepository lockCommitRepo,
			ReconcileSnapshotHeaderRepository reconcileHeaderRepo,
			ReconcileSnapshotCommitRepository reconcileCommitRepo, ObjectMapper objectMapper) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.workItemRepo = workItemRepo;
		this.eventRepo = eventRepo;
		this.lockHeaderRepo = lockHeaderRepo;
		this.lockCommitRepo = lockCommitRepo;
		this.reconcileHeaderRepo = reconcileHeaderRepo;
		this.reconcileCommitRepo = reconcileCommitRepo;
		this.objectMapper = objectMapper;
	}

	// -------------------------------------------------------------------------
	// Open reconciliation (LOCKED → RECONCILING)
	// -------------------------------------------------------------------------

	/**
	 * Transitions a LOCKED plan to RECONCILING. Idempotent: if already RECONCILING
	 * the call is a no-op.
	 *
	 * <p>
	 * Side-effect: any commit whose linked work-item has status DONE is
	 * automatically given an ACHIEVED outcome.
	 *
	 * @throws PlanValidationException
	 *             if the plan is not LOCKED or RECONCILING.
	 */
	public void openReconciliation(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);

		if (plan.getState() == PlanState.RECONCILING) {
			return; // idempotent
		}

		if (plan.getState() != PlanState.LOCKED) {
			throw new PlanValidationException(
					"Reconciliation can only be opened for LOCKED plans; current state: " + plan.getState());
		}

		plan.setState(PlanState.RECONCILING);
		planRepo.save(plan);

		autoAchieveDoneTickets(plan.getId());
	}

	// -------------------------------------------------------------------------
	// Reconciliation view
	// -------------------------------------------------------------------------

	/**
	 * Builds the full reconciliation dashboard for a RECONCILING (or RECONCILED)
	 * plan.
	 */
	@Transactional(readOnly = true)
	public ReconciliationViewResponse getReconciliationView(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.RECONCILING && plan.getState() != PlanState.RECONCILED) {
			throw new PlanValidationException(
					"Reconciliation view is only available for plans in RECONCILING or RECONCILED state; "
							+ "current state: " + plan.getState());
		}

		// Baseline data
		LockSnapshotHeader lockHeader = lockHeaderRepo.findByPlanId(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Lock snapshot not found for plan: " + planId));
		List<LockSnapshotCommit> lockCommits = lockCommitRepo.findBySnapshotId(lockHeader.getId());
		Map<UUID, Map<String, Object>> baselineByCommitId = buildBaselineMap(lockCommits);
		int baselineTotalPoints = baselineByCommitId.values().stream()
				.mapToInt(m -> m.get("estimatePoints") instanceof Number n ? n.intValue() : 0).sum();

		// Current commits
		List<WeeklyCommit> currentCommits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);

		// Scope-change events, grouped by commit
		List<ScopeChangeEvent> allEvents = eventRepo.findByPlanIdOrderByCreatedAtAsc(planId);
		Map<UUID, List<ScopeChangeEvent>> eventsByCommit = allEvents.stream().filter(e -> e.getCommitId() != null)
				.collect(Collectors.groupingBy(ScopeChangeEvent::getCommitId));

		// Identify commits added or removed post-lock
		Set<UUID> addedPostLock = allEvents.stream()
				.filter(e -> e.getCategory() == ScopeChangeCategory.COMMIT_ADDED && e.getCommitId() != null)
				.map(ScopeChangeEvent::getCommitId).collect(Collectors.toSet());
		Set<UUID> removedPostLock = allEvents.stream()
				.filter(e -> e.getCategory() == ScopeChangeCategory.COMMIT_REMOVED && e.getCommitId() != null)
				.map(ScopeChangeEvent::getCommitId).collect(Collectors.toSet());

		List<ReconcileCommitView> views = new ArrayList<>();
		int currentTotalPoints = 0;
		int outcomesSetCount = 0;

		for (WeeklyCommit commit : currentCommits) {
			int pts = commit.getEstimatePoints() != null ? commit.getEstimatePoints() : 0;
			if (commit.getOutcome() != CommitOutcome.CANCELED) {
				currentTotalPoints += pts;
			}
			if (commit.getOutcome() != null) {
				outcomesSetCount++;
			}

			List<ScopeChangeEventResponse> commitEvents = eventsByCommit.getOrDefault(commit.getId(), List.of())
					.stream().map(ScopeChangeEventResponse::from).toList();

			String ticketStatus = null;
			if (commit.getWorkItemId() != null) {
				ticketStatus = workItemRepo.findById(commit.getWorkItemId()).map(wi -> wi.getStatus().name())
						.orElse(null);
			}

			Map<String, Object> baseline = baselineByCommitId.get(commit.getId());

			views.add(new ReconcileCommitView(commit.getId(), commit.getTitle(), commit.getChessPiece(),
					commit.getEstimatePoints(), commit.getOutcome(), commit.getOutcomeNotes(), baseline, commitEvents,
					ticketStatus, addedPostLock.contains(commit.getId()), removedPostLock.contains(commit.getId())));
		}

		return new ReconciliationViewResponse(PlanResponse.from(plan), views, baselineTotalPoints, currentTotalPoints,
				currentCommits.size(), outcomesSetCount);
	}

	// -------------------------------------------------------------------------
	// Set commit outcome
	// -------------------------------------------------------------------------

	/**
	 * Sets (or updates) the outcome on a commit during RECONCILING.
	 *
	 * @throws PlanValidationException
	 *             if notes are required but absent.
	 */
	public CommitResponse setCommitOutcome(UUID planId, UUID commitId, CommitOutcome outcome, String notes) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.RECONCILING) {
			throw new PlanValidationException(
					"Outcomes can only be set while the plan is in RECONCILING state; current state: "
							+ plan.getState());
		}

		WeeklyCommit commit = requireCommit(commitId);
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commitId + " does not belong to plan " + planId);
		}

		// Notes required for PARTIALLY_ACHIEVED, NOT_ACHIEVED, CANCELED
		if (NOTES_REQUIRED_OUTCOMES.contains(outcome) && (notes == null || notes.isBlank())) {
			throw new PlanValidationException("Outcome notes are required for outcome " + outcome);
		}

		commit.setOutcome(outcome);
		commit.setOutcomeNotes(notes);
		commitRepo.save(commit);

		return CommitResponse.from(commit);
	}

	// -------------------------------------------------------------------------
	// Submit reconciliation
	// -------------------------------------------------------------------------

	/**
	 * Validates that all commits have outcomes, then writes the immutable
	 * reconciliation snapshot and transitions the plan to RECONCILED.
	 *
	 * @throws PlanValidationException
	 *             if any commit still has no outcome.
	 */
	public ReconciliationViewResponse submitReconciliation(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.RECONCILING) {
			throw new PlanValidationException(
					"Reconciliation can only be submitted from RECONCILING state; current state: " + plan.getState());
		}

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);

		// Validate every commit has an outcome
		List<UUID> missing = commits.stream().filter(c -> c.getOutcome() == null).map(WeeklyCommit::getId).toList();
		if (!missing.isEmpty()) {
			throw new PlanValidationException(
					"All commits must have an outcome before reconciliation can be submitted. "
							+ "Commits without outcomes: " + missing);
		}

		// Compute compliance: plan was already marked compliant/non-compliant at lock
		// time; we keep that flag and add an additional "all achieved" flag via the
		// snapshot payload.
		boolean allAchieved = commits.stream()
				.allMatch(c -> c.getOutcome() == CommitOutcome.ACHIEVED || c.getOutcome() == CommitOutcome.CANCELED);

		// Write immutable reconcile snapshot
		ReconcileSnapshotHeader header = new ReconcileSnapshotHeader();
		header.setPlanId(planId);
		header.setSnapshotPayload(buildReconcilePayload(plan, commits, allAchieved));
		ReconcileSnapshotHeader savedHeader = reconcileHeaderRepo.save(header);

		for (WeeklyCommit commit : commits) {
			ReconcileSnapshotCommit sc = new ReconcileSnapshotCommit();
			sc.setSnapshotId(savedHeader.getId());
			sc.setCommitId(commit.getId());
			sc.setOutcome(commit.getOutcome());
			sc.setSnapshotData(buildCommitSnapshot(commit));
			reconcileCommitRepo.save(sc);
		}

		// Transition to RECONCILED
		plan.setReconcileSnapshotId(savedHeader.getId());
		plan.setState(PlanState.RECONCILED);
		plan.setCompliant(plan.isCompliant() && allAchieved);
		planRepo.save(plan);

		return getReconciliationView(planId);
	}

	// -------------------------------------------------------------------------
	// Auto-achieve helper (called by openReconciliation)
	// -------------------------------------------------------------------------

	private void autoAchieveDoneTickets(UUID planId) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		for (WeeklyCommit commit : commits) {
			if (commit.getWorkItemId() != null && commit.getOutcome() == null) {
				Optional<WorkItem> wiOpt = workItemRepo.findById(commit.getWorkItemId());
				if (wiOpt.isPresent() && wiOpt.get().getStatus() == TicketStatus.DONE) {
					commit.setOutcome(CommitOutcome.ACHIEVED);
					commitRepo.save(commit);
				}
			}
		}
	}

	// -------------------------------------------------------------------------
	// Snapshot builders
	// -------------------------------------------------------------------------

	private String buildReconcilePayload(WeeklyPlan plan, List<WeeklyCommit> commits, boolean allAchieved) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("planId", plan.getId().toString());
		m.put("ownerUserId", plan.getOwnerUserId().toString());
		m.put("teamId", plan.getTeamId().toString());
		m.put("weekStartDate", plan.getWeekStartDate().toString());
		m.put("reconciledAt", Instant.now().toString());
		m.put("allAchieved", allAchieved);
		m.put("commits", commits.stream().map(this::commitToMapForSnapshot).toList());
		return toJson(m);
	}

	private String buildCommitSnapshot(WeeklyCommit commit) {
		return toJson(commitToMapForSnapshot(commit));
	}

	private Map<String, Object> commitToMapForSnapshot(WeeklyCommit commit) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("id", commit.getId().toString());
		m.put("title", commit.getTitle());
		m.put("chessPiece", commit.getChessPiece() != null ? commit.getChessPiece().name() : null);
		m.put("priorityOrder", commit.getPriorityOrder());
		m.put("estimatePoints", commit.getEstimatePoints());
		m.put("successCriteria", commit.getSuccessCriteria());
		m.put("outcome", commit.getOutcome() != null ? commit.getOutcome().name() : null);
		m.put("outcomeNotes", commit.getOutcomeNotes());
		m.put("rcdoNodeId", commit.getRcdoNodeId() != null ? commit.getRcdoNodeId().toString() : null);
		m.put("workItemId", commit.getWorkItemId() != null ? commit.getWorkItemId().toString() : null);
		return m;
	}

	// -------------------------------------------------------------------------
	// Baseline map builder
	// -------------------------------------------------------------------------

	private Map<UUID, Map<String, Object>> buildBaselineMap(List<LockSnapshotCommit> lockCommits) {
		Map<UUID, Map<String, Object>> result = new HashMap<>();
		for (LockSnapshotCommit lsc : lockCommits) {
			try {
				JsonNode node = objectMapper.readTree(lsc.getSnapshotData());
				Map<String, Object> m = new LinkedHashMap<>();
				node.fields().forEachRemaining(entry -> m.put(entry.getKey(), nodeToValue(entry.getValue())));
				result.put(lsc.getCommitId(), m);
			} catch (JsonProcessingException e) {
				// return empty map for this commit if JSON is malformed
				result.put(lsc.getCommitId(), Map.of());
			}
		}
		return result;
	}

	private Object nodeToValue(JsonNode node) {
		if (node.isNull())
			return null;
		if (node.isInt())
			return node.intValue();
		if (node.isLong())
			return node.longValue();
		if (node.isBoolean())
			return node.booleanValue();
		if (node.isTextual())
			return node.textValue();
		return node.toString();
	}

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan requirePlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private String toJson(Object o) {
		try {
			return objectMapper.writeValueAsString(o);
		} catch (JsonProcessingException e) {
			throw new IllegalStateException("JSON serialisation failed", e);
		}
	}
}

package com.weeklycommit.reconcile.service;

import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import java.time.Instant;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

/**
 * Scheduled job that opens reconciliation for LOCKED plans whose reconcile-open
 * deadline has passed.
 *
 * <p>
 * Each plan is processed in its own transaction (delegated to
 * {@link ReconciliationService#openReconciliation}) so a failure on one plan
 * does not prevent the others from being processed.
 *
 * <p>
 * The job is idempotent: plans already in RECONCILING state are skipped by the
 * service delegate.
 */
@Component
public class AutoReconcileJob {

	private static final Logger log = LoggerFactory.getLogger(AutoReconcileJob.class);

	private final WeeklyPlanRepository planRepo;
	private final ReconciliationService reconciliationService;

	public AutoReconcileJob(WeeklyPlanRepository planRepo, ReconciliationService reconciliationService) {
		this.planRepo = planRepo;
		this.reconciliationService = reconciliationService;
	}

	/**
	 * Runs every minute. Finds LOCKED plans past their reconcile deadline and opens
	 * reconciliation for each.
	 */
	@Scheduled(cron = "0 * * * * *")
	public void openExpiredReconciliations() {
		Instant now = Instant.now();
		List<UUID> expired = planRepo.findByStateAndReconcileDeadlineBefore(PlanState.LOCKED, now).stream()
				.map(p -> p.getId()).collect(Collectors.toList());

		if (expired.isEmpty()) {
			return;
		}

		log.info("Auto-reconcile job: {} expired LOCKED plan(s) to open for reconciliation", expired.size());

		for (UUID planId : expired) {
			try {
				reconciliationService.openReconciliation(planId);
				log.info("Opened reconciliation for plan {}", planId);
			} catch (Exception ex) {
				log.error("Failed to open reconciliation for plan {}: {}", planId, ex.getMessage(), ex);
			}
		}
	}
}

package com.weeklycommit.reconcile.controller;

import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.reconcile.dto.ReconciliationViewResponse;
import com.weeklycommit.reconcile.dto.ScopeChangeRequest;
import com.weeklycommit.reconcile.dto.ScopeChangeTimelineResponse;
import com.weeklycommit.reconcile.dto.SetOutcomeRequest;
import com.weeklycommit.reconcile.service.ReconciliationService;
import com.weeklycommit.reconcile.service.ScopeChangeService;
import jakarta.validation.Valid;
import java.util.UUID;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for post-lock scope changes and reconciliation.
 *
 * <p>
 * All routes are under {@code /api/plans/{id}} consistent with the existing
 * plan controller namespace.
 */
@RestController
@RequestMapping("/api/plans")
public class ReconcileController {

	private final ScopeChangeService scopeChangeService;
	private final ReconciliationService reconciliationService;

	public ReconcileController(ScopeChangeService scopeChangeService, ReconciliationService reconciliationService) {
		this.scopeChangeService = scopeChangeService;
		this.reconciliationService = reconciliationService;
	}

	// -------------------------------------------------------------------------
	// POST /api/plans/{id}/scope-changes — add / remove / edit post-lock
	// -------------------------------------------------------------------------

	/**
	 * Routes to the appropriate scope-change operation based on the {@code action}
	 * field in the request body.
	 *
	 * <ul>
	 * <li>ADD — adds a new commit to a LOCKED plan.</li>
	 * <li>REMOVE — cancels an existing baseline commit.</li>
	 * <li>EDIT — patches mutable fields on a baseline commit.</li>
	 * </ul>
	 */
	@PostMapping("/{id}/scope-changes")
	public ResponseEntity<ScopeChangeTimelineResponse> applyScopeChange(@PathVariable UUID id,
			@Valid @RequestBody ScopeChangeRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {

		ScopeChangeTimelineResponse result = switch (request.action()) {
			case ADD -> scopeChangeService.addPostLockCommit(id, request.commitData(), request.reason(), actorUserId);
			case REMOVE -> scopeChangeService.removePostLockCommit(request.commitId(), request.reason(), actorUserId);
			case EDIT -> scopeChangeService.editPostLockCommit(request.commitId(), request.changes(), request.reason(),
					actorUserId);
		};

		return ResponseEntity.ok(result);
	}

	// -------------------------------------------------------------------------
	// GET /api/plans/{id}/scope-changes — change timeline
	// -------------------------------------------------------------------------

	/** Returns the chronological list of scope-change events for a plan. */
	@GetMapping("/{id}/scope-changes")
	public ResponseEntity<ScopeChangeTimelineResponse> getChangeTimeline(@PathVariable UUID id) {
		return ResponseEntity.ok(scopeChangeService.getChangeTimeline(id));
	}

	// -------------------------------------------------------------------------
	// GET /api/plans/{id}/reconcile — reconciliation view
	// -------------------------------------------------------------------------

	/** Returns the full reconciliation view (baseline vs current). */
	@GetMapping("/{id}/reconcile")
	public ResponseEntity<ReconciliationViewResponse> getReconciliationView(@PathVariable UUID id) {
		return ResponseEntity.ok(reconciliationService.getReconciliationView(id));
	}

	// -------------------------------------------------------------------------
	// PUT /api/plans/{id}/commits/{commitId}/outcome — set outcome
	// -------------------------------------------------------------------------

	/** Sets (or updates) the outcome for a single commit. */
	@PutMapping("/{id}/commits/{commitId}/outcome")
	public ResponseEntity<CommitResponse> setCommitOutcome(@PathVariable UUID id, @PathVariable UUID commitId,
			@Valid @RequestBody SetOutcomeRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		CommitResponse response = reconciliationService.setCommitOutcome(id, commitId, request.outcome(),
				request.notes());
		return ResponseEntity.ok(response);
	}

	// -------------------------------------------------------------------------
	// POST /api/plans/{id}/reconcile/submit — submit reconciliation
	// -------------------------------------------------------------------------

	/**
	 * Finalises reconciliation: validates, snapshots, and transitions to
	 * RECONCILED.
	 */
	@PostMapping("/{id}/reconcile/submit")
	public ResponseEntity<ReconciliationViewResponse> submitReconciliation(@PathVariable UUID id,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		return ResponseEntity.ok(reconciliationService.submitReconciliation(id));
	}
}

