package com.weeklycommit.carryforward.service;

import com.weeklycommit.carryforward.dto.CarryForwardLinkResponse;
import com.weeklycommit.carryforward.dto.CarryForwardLineageResponse;
import com.weeklycommit.carryforward.dto.CarryForwardResponse;
import com.weeklycommit.domain.entity.CarryForwardLink;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.CarryForwardReason;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.enums.ScopeChangeCategory;
import com.weeklycommit.domain.repository.CarryForwardLinkRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.plan.service.WeeklyPlanService;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.LocalDate;
import java.time.ZoneOffset;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Implements PRD §13 FR-6 — carry-forward logic.
 *
 * <p>
 * A carry-forward copies a commit's core fields into a new commit in a target
 * week's plan, preserving provenance via a {@link CarryForwardLink}. The streak
 * counter tracks how many consecutive weeks a commit has been carried forward.
 */
@Service
@Transactional
public class CarryForwardService {

	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final UserAccountRepository userRepo;
	private final CarryForwardLinkRepository linkRepo;
	private final ScopeChangeEventRepository scopeChangeEventRepo;

	public CarryForwardService(WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo,
			UserAccountRepository userRepo, CarryForwardLinkRepository linkRepo,
			ScopeChangeEventRepository scopeChangeEventRepo) {
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.userRepo = userRepo;
		this.linkRepo = linkRepo;
		this.scopeChangeEventRepo = scopeChangeEventRepo;
	}

	// -------------------------------------------------------------------------
	// carryForward
	// -------------------------------------------------------------------------

	/**
	 * Carries a commit forward into the target week's plan.
	 *
	 * <ul>
	 * <li>Copies title, description, chess piece, RCDO link, estimate points.</li>
	 * <li>Sets {@code carryForwardSourceId} and increments
	 * {@code carryForwardStreak} (source streak + 1).</li>
	 * <li>New commit is inserted at the bottom of the target plan's priority
	 * order.</li>
	 * <li>If the target week plan does not exist, it is lazily created.</li>
	 * <li>If the target plan is already LOCKED, the commit is added as a post-lock
	 * scope change event (COMMIT_ADDED with carry-forward reason).</li>
	 * </ul>
	 *
	 * @param sourceCommitId
	 *            commit to carry forward
	 * @param targetWeekStart
	 *            Monday of the target week
	 * @param reason
	 *            controlled enum reason
	 * @param reasonText
	 *            optional free-text elaboration
	 * @param actorUserId
	 *            user initiating the operation
	 * @return carry-forward response with new commit and provenance link
	 */
	public CarryForwardResponse carryForward(UUID sourceCommitId, LocalDate targetWeekStart, CarryForwardReason reason,
			String reasonText, UUID actorUserId) {

		WeeklyCommit source = requireCommit(sourceCommitId);
		UUID ownerUserId = source.getOwnerUserId();

		// Get or lazily create the target week plan
		WeeklyPlan targetPlan = getOrCreateTargetPlan(ownerUserId, targetWeekStart);
		boolean postLockAdded = targetPlan.getState() == PlanState.LOCKED;

		// Build the new commit (provenance fields set regardless of plan state)
		WeeklyCommit newCommit = buildNewCommit(source, targetPlan);
		WeeklyCommit saved = commitRepo.save(newCommit);

		// If the target plan is LOCKED, record a scope-change event
		if (postLockAdded) {
			recordCarryForwardScopeChangeEvent(targetPlan.getId(), saved, reason, reasonText, actorUserId);
		}

		// Persist the provenance link
		CarryForwardLink link = new CarryForwardLink();
		link.setSourceCommitId(sourceCommitId);
		link.setTargetCommitId(saved.getId());
		link.setReason(reason);
		link.setReasonNotes(reasonText);
		CarryForwardLink savedLink = linkRepo.save(link);

		return new CarryForwardResponse(CommitResponse.from(saved), CarryForwardLinkResponse.from(savedLink),
				postLockAdded);
	}

	// -------------------------------------------------------------------------
	// getCarryForwardLineage
	// -------------------------------------------------------------------------

	/**
	 * Returns the full carry-forward ancestry chain for {@code commitId}.
	 *
	 * <p>
	 * Traverses both ancestors (via {@code carryForwardSourceId} on the commit
	 * entity) and descendants (via {@link CarryForwardLinkRepository}) to produce a
	 * complete, ordered chain from the oldest ancestor to the youngest descendant.
	 *
	 * @param commitId
	 *            starting commit
	 * @return full lineage ordered oldest-first
	 */
	@Transactional(readOnly = true)
	public CarryForwardLineageResponse getCarryForwardLineage(UUID commitId) {
		requireCommit(commitId);

		// Walk ancestors (upward)
		List<CarryForwardLink> ancestors = new LinkedList<>();
		UUID cursor = commitId;
		while (true) {
			WeeklyCommit c = commitRepo.findById(cursor).orElse(null);
			if (c == null || c.getCarryForwardSourceId() == null) {
				break;
			}
			Optional<CarryForwardLink> link = linkRepo.findByTargetCommitId(cursor);
			link.ifPresent(l -> ancestors.add(0, l)); // prepend — oldest first
			cursor = c.getCarryForwardSourceId();
		}
		UUID rootCommitId = cursor;

		// Walk descendants (downward) starting from commitId
		List<CarryForwardLink> descendants = new ArrayList<>();
		cursor = commitId;
		while (true) {
			List<CarryForwardLink> links = linkRepo.findBySourceCommitId(cursor);
			if (links.isEmpty()) {
				break;
			}
			// Take the first descendant (one-to-one chain is the normal case)
			CarryForwardLink next = links.get(0);
			descendants.add(next);
			cursor = next.getTargetCommitId();
		}

		List<CarryForwardLink> chain = new ArrayList<>();
		chain.addAll(ancestors);
		chain.addAll(descendants);

		List<CarryForwardLinkResponse> responses = chain.stream().map(CarryForwardLinkResponse::from).toList();
		return new CarryForwardLineageResponse(rootCommitId, responses);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	/**
	 * Fetches an existing plan for the owner+week or lazily creates one. This
	 * mirrors the logic in {@link WeeklyPlanService} but is intentionally
	 * self-contained to avoid a circular service dependency.
	 */
	private WeeklyPlan getOrCreateTargetPlan(UUID ownerUserId, LocalDate targetWeekStart) {
		return planRepo.findByOwnerUserIdAndWeekStartDate(ownerUserId, targetWeekStart)
				.orElseGet(() -> createTargetPlan(ownerUserId, targetWeekStart));
	}

	private WeeklyPlan createTargetPlan(UUID ownerUserId, LocalDate weekStartDate) {
		UserAccount user = userRepo.findById(ownerUserId)
				.orElseThrow(() -> new ResourceNotFoundException("User not found: " + ownerUserId));

		if (user.getHomeTeamId() == null) {
			throw new PlanValidationException(
					"User " + ownerUserId + " has no home team; cannot create a carry-forward plan");
		}

		WeeklyPlan plan = new WeeklyPlan();
		plan.setOwnerUserId(ownerUserId);
		plan.setTeamId(user.getHomeTeamId());
		plan.setWeekStartDate(weekStartDate);
		plan.setState(PlanState.DRAFT);
		plan.setCapacityBudgetPoints(user.getWeeklyCapacityPoints());
		plan.setLockDeadline(weekStartDate.atTime(12, 0).toInstant(ZoneOffset.UTC));
		plan.setReconcileDeadline(weekStartDate.plusDays(7).atTime(10, 0).toInstant(ZoneOffset.UTC));
		return planRepo.save(plan);
	}

	private WeeklyCommit buildNewCommit(WeeklyCommit source, WeeklyPlan targetPlan) {
		WeeklyCommit c = new WeeklyCommit();
		c.setPlanId(targetPlan.getId());
		c.setOwnerUserId(source.getOwnerUserId());
		c.setTitle(source.getTitle());
		c.setDescription(source.getDescription());
		c.setChessPiece(source.getChessPiece());
		c.setRcdoNodeId(source.getRcdoNodeId());
		c.setEstimatePoints(source.getEstimatePoints());
		c.setSuccessCriteria(source.getSuccessCriteria());
		// Provenance
		c.setCarryForwardSourceId(source.getId());
		c.setCarryForwardStreak(source.getCarryForwardStreak() + 1);
		// Bottom of priority order
		c.setPriorityOrder((int) (commitRepo.countByPlanId(targetPlan.getId()) + 1));
		return c;
	}

	/**
	 * Records a COMMIT_ADDED scope-change event when carry-forward targets a LOCKED
	 * plan.
	 */
	private void recordCarryForwardScopeChangeEvent(UUID planId, WeeklyCommit commit, CarryForwardReason reason,
			String reasonText, UUID actorUserId) {
		ScopeChangeEvent event = new ScopeChangeEvent();
		event.setPlanId(planId);
		event.setCommitId(commit.getId());
		event.setCategory(ScopeChangeCategory.COMMIT_ADDED);
		event.setChangedByUserId(
				actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		String reasonLabel = "CARRY_FORWARD:" + reason.name() + (reasonText != null ? " — " + reasonText : "");
		event.setReason(reasonLabel);
		event.setPreviousValue(null);
		// Minimal JSON payload matching what ScopeChangeService would produce
		event.setNewValue("{\"carryForward\":true,\"chessPiece\":\""
				+ (commit.getChessPiece() != null ? commit.getChessPiece().name() : "") + "\",\"title\":"
				+ quoteJson(commit.getTitle()) + "}");
		scopeChangeEventRepo.save(event);
	}

	private static String quoteJson(String s) {
		if (s == null) {
			return "null";
		}
		return "\"" + s.replace("\\", "\\\\").replace("\"", "\\\"") + "\"";
	}
}

package com.weeklycommit.carryforward.controller;

import com.weeklycommit.carryforward.dto.CarryForwardLineageResponse;
import com.weeklycommit.carryforward.dto.CarryForwardRequest;
import com.weeklycommit.carryforward.dto.CarryForwardResponse;
import com.weeklycommit.carryforward.service.CarryForwardService;
import jakarta.validation.Valid;
import java.util.UUID;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for carry-forward operations.
 *
 * <ul>
 * <li>{@code POST /api/plans/{id}/commits/{commitId}/carry-forward} — carry a
 * commit forward into a target week</li>
 * <li>{@code GET /api/commits/{id}/lineage} — retrieve the full carry-forward
 * ancestry chain</li>
 * </ul>
 */
@RestController
public class CarryForwardController {

	private final CarryForwardService carryForwardService;

	public CarryForwardController(CarryForwardService carryForwardService) {
		this.carryForwardService = carryForwardService;
	}

	/**
	 * Carries a commit forward into the target week's plan.
	 *
	 * @param planId
	 *            plan that currently owns the commit (path binding only — verified
	 *            server-side against the commit's plan)
	 * @param commitId
	 *            commit to carry forward
	 * @param request
	 *            target week, reason, and optional free-text
	 * @param actorId
	 *            actor user ID from header (falls back to request.actorUserId())
	 * @return 201 Created with the new commit and provenance link
	 */
	@PostMapping("/api/plans/{planId}/commits/{commitId}/carry-forward")
	public ResponseEntity<CarryForwardResponse> carryForward(@PathVariable UUID planId, @PathVariable UUID commitId,
			@Valid @RequestBody CarryForwardRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorId) {

		UUID actor = actorId != null ? actorId : request.actorUserId();
		CarryForwardResponse response = carryForwardService.carryForward(commitId, request.targetWeekStart(),
				request.reason(), request.reasonText(), actor);
		return ResponseEntity.status(HttpStatus.CREATED).body(response);
	}

	/**
	 * Returns the full carry-forward ancestry chain for a commit.
	 *
	 * @param commitId
	 *            starting commit (may be any point in the chain)
	 * @return lineage ordered oldest-first
	 */
	@GetMapping("/api/commits/{commitId}/lineage")
	public ResponseEntity<CarryForwardLineageResponse> getLineage(@PathVariable UUID commitId) {
		return ResponseEntity.ok(carryForwardService.getCarryForwardLineage(commitId));
	}
}

package com.weeklycommit.ticket.service;

import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.entity.WorkItemStatusHistory;
import com.weeklycommit.domain.enums.TicketStatus;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.domain.repository.WorkItemStatusHistoryRepository;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.ticket.dto.CreateTicketRequest;
import com.weeklycommit.ticket.dto.TicketResponse;
import com.weeklycommit.ticket.dto.TicketStatusHistoryResponse;
import com.weeklycommit.ticket.dto.UpdateTicketRequest;
import java.util.EnumSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * CRUD and status-workflow service for native tickets (work items).
 *
 * <p>
 * Status transitions are enforced via a static transition map. Every status
 * change is appended to {@code work_item_status_history} for duration-in-status
 * reporting.
 */
@Service
@Transactional
public class TicketService {

	/** Valid Fibonacci-scale estimate values (mirrors CommitService). */
	private static final Set<Integer> VALID_ESTIMATE_POINTS = Set.of(1, 2, 3, 5, 8);

	/** Key prefix used when auto-generating ticket keys. */
	private static final String KEY_PREFIX = "T-";

	/**
	 * Legal status transitions.
	 *
	 * <pre>
	 * BACKLOG     → READY, IN_PROGRESS, CANCELED
	 * READY       → IN_PROGRESS, BACKLOG, CANCELED
	 * IN_PROGRESS → DONE, BLOCKED, READY, CANCELED
	 * BLOCKED     → IN_PROGRESS, CANCELED
	 * DONE        → (terminal)
	 * CANCELED    → (terminal)
	 * </pre>
	 */
	private static final Map<TicketStatus, Set<TicketStatus>> ALLOWED_TRANSITIONS = Map.of(TicketStatus.BACKLOG,
			EnumSet.of(TicketStatus.READY, TicketStatus.IN_PROGRESS, TicketStatus.CANCELED), TicketStatus.READY,
			EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.BACKLOG, TicketStatus.CANCELED), TicketStatus.IN_PROGRESS,
			EnumSet.of(TicketStatus.DONE, TicketStatus.BLOCKED, TicketStatus.READY, TicketStatus.CANCELED),
			TicketStatus.BLOCKED, EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.CANCELED), TicketStatus.DONE,
			EnumSet.noneOf(TicketStatus.class), TicketStatus.CANCELED, EnumSet.noneOf(TicketStatus.class));

	private final WorkItemRepository workItemRepo;
	private final WorkItemStatusHistoryRepository historyRepo;

	public TicketService(WorkItemRepository workItemRepo, WorkItemStatusHistoryRepository historyRepo) {
		this.workItemRepo = workItemRepo;
		this.historyRepo = historyRepo;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	/**
	 * Creates a new ticket with an auto-generated key of the form {@code T-N}.
	 *
	 * @param req
	 *            creation request
	 * @return saved ticket
	 */
	public TicketResponse createTicket(CreateTicketRequest req) {
		validateEstimatePoints(req.estimatePoints());

		WorkItem item = new WorkItem();
		item.setTeamId(req.teamId());
		item.setKey(generateKey(req.teamId()));
		item.setTitle(req.title());
		item.setDescription(req.description());
		item.setStatus(TicketStatus.BACKLOG);
		item.setAssigneeUserId(req.assigneeUserId());
		item.setReporterUserId(req.reporterUserId());
		item.setEstimatePoints(req.estimatePoints());
		item.setRcdoNodeId(req.rcdoNodeId());
		item.setTargetWeekStartDate(req.targetWeekStartDate());

		return TicketResponse.from(workItemRepo.save(item));
	}

	// -------------------------------------------------------------------------
	// Read
	// -------------------------------------------------------------------------

	/**
	 * Fetches a single ticket by its ID.
	 *
	 * @param id
	 *            ticket identifier
	 * @return ticket view
	 * @throws ResourceNotFoundException
	 *             if not found
	 */
	@Transactional(readOnly = true)
	public TicketResponse getTicket(UUID id) {
		return TicketResponse.from(requireTicket(id));
	}

	/**
	 * Lists all tickets for a team.
	 *
	 * @param teamId
	 *            team identifier
	 * @return list of ticket views
	 */
	@Transactional(readOnly = true)
	public List<TicketResponse> listTicketsByTeam(UUID teamId) {
		return workItemRepo.findByTeamId(teamId).stream().map(TicketResponse::from).toList();
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	/**
	 * Partially updates a ticket. {@code null} fields in the request are ignored.
	 *
	 * @param id
	 *            ticket identifier
	 * @param req
	 *            partial update
	 * @return updated ticket view
	 */
	public TicketResponse updateTicket(UUID id, UpdateTicketRequest req) {
		WorkItem item = requireTicket(id);

		if (req.title() != null && !req.title().isBlank()) {
			item.setTitle(req.title());
		}
		if (req.description() != null) {
			item.setDescription(req.description());
		}
		if (req.assigneeUserId() != null) {
			item.setAssigneeUserId(req.assigneeUserId());
		}
		if (req.estimatePoints() != null) {
			validateEstimatePoints(req.estimatePoints());
			item.setEstimatePoints(req.estimatePoints());
		}
		if (req.rcdoNodeId() != null) {
			item.setRcdoNodeId(req.rcdoNodeId());
		}
		if (req.targetWeekStartDate() != null) {
			item.setTargetWeekStartDate(req.targetWeekStartDate());
		}

		return TicketResponse.from(workItemRepo.save(item));
	}

	// -------------------------------------------------------------------------
	// Update status
	// -------------------------------------------------------------------------

	/**
	 * Transitions the ticket to a new status, validating the transition and
	 * recording history.
	 *
	 * @param id
	 *            ticket identifier
	 * @param newStatus
	 *            target status
	 * @param changedByUserId
	 *            user performing the transition
	 * @return updated ticket view
	 * @throws PlanValidationException
	 *             if the transition is not allowed
	 */
	public TicketResponse updateStatus(UUID id, TicketStatus newStatus, UUID changedByUserId) {
		WorkItem item = requireTicket(id);
		TicketStatus currentStatus = item.getStatus();

		if (currentStatus == newStatus) {
			return TicketResponse.from(item); // idempotent — no change
		}

		Set<TicketStatus> allowed = ALLOWED_TRANSITIONS.getOrDefault(currentStatus, EnumSet.noneOf(TicketStatus.class));
		if (!allowed.contains(newStatus)) {
			throw new PlanValidationException(
					"Illegal ticket status transition: " + currentStatus + " → " + newStatus + ". Allowed: " + allowed);
		}

		// Record history before updating the entity
		WorkItemStatusHistory history = new WorkItemStatusHistory();
		history.setWorkItemId(id);
		history.setFromStatus(currentStatus.name());
		history.setToStatus(newStatus.name());
		history.setChangedByUserId(changedByUserId);
		historyRepo.save(history);

		item.setStatus(newStatus);
		return TicketResponse.from(workItemRepo.save(item));
	}

	// -------------------------------------------------------------------------
	// Status history
	// -------------------------------------------------------------------------

	/**
	 * Returns the full status-change history for a ticket, ordered chronologically.
	 *
	 * @param id
	 *            ticket identifier
	 * @return ordered list of status history entries
	 */
	@Transactional(readOnly = true)
	public List<TicketStatusHistoryResponse> getStatusHistory(UUID id) {
		requireTicket(id); // ensure ticket exists
		return historyRepo.findByWorkItemIdOrderByCreatedAtAsc(id).stream().map(TicketStatusHistoryResponse::from)
				.toList();
	}

	// -------------------------------------------------------------------------
	// Delete
	// -------------------------------------------------------------------------

	/**
	 * Hard-deletes a ticket.
	 *
	 * @param id
	 *            ticket identifier
	 * @throws ResourceNotFoundException
	 *             if not found
	 */
	public void deleteTicket(UUID id) {
		WorkItem item = requireTicket(id);
		workItemRepo.delete(item);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	WorkItem requireTicket(UUID id) {
		return workItemRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Ticket not found: " + id));
	}

	/**
	 * Generates a unique key for a ticket within its team. Uses a simple sequential
	 * counter based on the total number of tickets in the team.
	 */
	private String generateKey(UUID teamId) {
		long count = workItemRepo.countByTeamId(teamId);
		return KEY_PREFIX + (count + 1);
	}

	static void validateEstimatePoints(Integer points) {
		if (points != null && !VALID_ESTIMATE_POINTS.contains(points)) {
			throw new PlanValidationException("Estimate points must be one of {1, 2, 3, 5, 8}, got: " + points);
		}
	}
}

package com.weeklycommit.ticket.service;

import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.ticket.dto.LinkTicketResponse;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles linking a ticket (work item) to a commit with RCDO defaulting and
 * same-week duplicate-link prevention.
 *
 * <p>
 * RCDO defaulting rules:
 * <ol>
 * <li>If the commit has no RCDO and the ticket has one, the commit inherits the
 * ticket's RCDO.</li>
 * <li>If both have an RCDO and they differ, a warning is included in the
 * response (but the link is still created).</li>
 * <li>If the commit already has an RCDO and the ticket has none, no change is
 * made.</li>
 * </ol>
 */
@Service
@Transactional
public class LinkTicketService {

	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final WorkItemRepository workItemRepo;

	public LinkTicketService(WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo,
			WorkItemRepository workItemRepo) {
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.workItemRepo = workItemRepo;
	}

	/**
	 * Links the given ticket to the given commit.
	 *
	 * <p>
	 * The plan must be in DRAFT state (post-lock ticket linking should go through
	 * scope-change flow). Prevents the same assignee from linking the same ticket
	 * to multiple active commits within the same week.
	 *
	 * @param planId
	 *            plan the commit belongs to
	 * @param commitId
	 *            commit to update
	 * @param workItemId
	 *            ticket to link
	 * @return updated commit plus any RCDO mismatch warning
	 */
	public LinkTicketResponse linkTicket(UUID planId, UUID commitId, UUID workItemId) {
		WeeklyCommit commit = requireCommit(commitId);
		validateCommitBelongsToPlan(planId, commit);
		requireDraftPlan(planId);

		WorkItem ticket = requireTicket(workItemId);

		// Duplicate-link prevention: same assignee, same ticket, this week, other
		// active commits
		List<WeeklyCommit> duplicates = commitRepo.findActiveCommitsForTicketByOwnerExcluding(workItemId,
				commit.getOwnerUserId(), commitId);

		// Filter to same-week duplicates
		WeeklyPlan currentPlan = requirePlan(planId);
		List<WeeklyCommit> sameWeekDuplicates = duplicates.stream().filter(c -> {
			WeeklyPlan p = planRepo.findById(c.getPlanId()).orElse(null);
			return p != null && currentPlan.getWeekStartDate().equals(p.getWeekStartDate());
		}).toList();

		if (!sameWeekDuplicates.isEmpty()) {
			throw new PlanValidationException(
					"Ticket " + workItemId + " is already linked to another active commit by the same assignee "
							+ "in week " + currentPlan.getWeekStartDate());
		}

		// RCDO defaulting and mismatch detection
		String rcdoWarning = null;
		UUID commitRcdo = commit.getRcdoNodeId();
		UUID ticketRcdo = ticket.getRcdoNodeId();

		if (commitRcdo == null && ticketRcdo != null) {
			// Default from ticket
			commit.setRcdoNodeId(ticketRcdo);
		} else if (commitRcdo != null && ticketRcdo != null && !commitRcdo.equals(ticketRcdo)) {
			// Mismatch warning — keep commit's existing RCDO
			rcdoWarning = "Commit RCDO (" + commitRcdo + ") differs from ticket RCDO (" + ticketRcdo
					+ "); commit RCDO was not changed";
		}

		commit.setWorkItemId(workItemId);
		WeeklyCommit saved = commitRepo.save(commit);

		return new LinkTicketResponse(CommitResponse.from(saved), rcdoWarning);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private WeeklyPlan requirePlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private void requireDraftPlan(UUID planId) {
		WeeklyPlan plan = requirePlan(planId);
		if (plan.getState() != PlanState.DRAFT) {
			throw new PlanValidationException(
					"Ticket linking is only allowed on DRAFT plans; current state: " + plan.getState());
		}
	}

	private WorkItem requireTicket(UUID workItemId) {
		return workItemRepo.findById(workItemId)
				.orElseThrow(() -> new ResourceNotFoundException("Ticket not found: " + workItemId));
	}

	private void validateCommitBelongsToPlan(UUID planId, WeeklyCommit commit) {
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commit.getId() + " does not belong to plan " + planId);
		}
	}
}

package com.weeklycommit.ticket.controller;

import com.weeklycommit.ticket.dto.CreateTicketRequest;
import com.weeklycommit.ticket.dto.LinkTicketRequest;
import com.weeklycommit.ticket.dto.LinkTicketResponse;
import com.weeklycommit.ticket.dto.TicketResponse;
import com.weeklycommit.ticket.dto.TicketStatusHistoryResponse;
import com.weeklycommit.ticket.dto.UpdateTicketRequest;
import com.weeklycommit.ticket.dto.UpdateTicketStatusRequest;
import com.weeklycommit.ticket.service.LinkTicketService;
import com.weeklycommit.ticket.service.TicketService;
import jakarta.validation.Valid;
import java.util.List;
import java.util.UUID;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for native ticket (work item) management.
 *
 * <ul>
 * <li>{@code GET  /api/tickets?teamId=…} — list tickets for a team</li>
 * <li>{@code POST /api/tickets} — create a ticket</li>
 * <li>{@code GET /api/tickets/{id}} — get a ticket</li>
 * <li>{@code PUT /api/tickets/{id}} — update a ticket</li>
 * <li>{@code DELETE /api/tickets/{id}} — delete a ticket</li>
 * <li>{@code PUT /api/tickets/{id}/status} — transition ticket status</li>
 * <li>{@code GET /api/tickets/{id}/history} — status history</li>
 * <li>{@code PUT /api/plans/{planId}/commits/{commitId}/link-ticket} — link
 * ticket to commit</li>
 * </ul>
 */
@RestController
public class TicketController {

	private final TicketService ticketService;
	private final LinkTicketService linkTicketService;

	public TicketController(TicketService ticketService, LinkTicketService linkTicketService) {
		this.ticketService = ticketService;
		this.linkTicketService = linkTicketService;
	}

	// -------------------------------------------------------------------------
	// Ticket CRUD
	// -------------------------------------------------------------------------

	/** List all tickets for a team. */
	@GetMapping("/api/tickets")
	public ResponseEntity<List<TicketResponse>> listTickets(@RequestParam UUID teamId) {
		return ResponseEntity.ok(ticketService.listTicketsByTeam(teamId));
	}

	/** Create a new ticket. */
	@PostMapping("/api/tickets")
	public ResponseEntity<TicketResponse> createTicket(@Valid @RequestBody CreateTicketRequest request) {
		return ResponseEntity.status(HttpStatus.CREATED).body(ticketService.createTicket(request));
	}

	/** Get a single ticket. */
	@GetMapping("/api/tickets/{id}")
	public ResponseEntity<TicketResponse> getTicket(@PathVariable UUID id) {
		return ResponseEntity.ok(ticketService.getTicket(id));
	}

	/** Partially update a ticket. */
	@PutMapping("/api/tickets/{id}")
	public ResponseEntity<TicketResponse> updateTicket(@PathVariable UUID id,
			@RequestBody UpdateTicketRequest request) {
		return ResponseEntity.ok(ticketService.updateTicket(id, request));
	}

	/** Delete a ticket. */
	@DeleteMapping("/api/tickets/{id}")
	public ResponseEntity<Void> deleteTicket(@PathVariable UUID id) {
		ticketService.deleteTicket(id);
		return ResponseEntity.noContent().build();
	}

	// -------------------------------------------------------------------------
	// Status transition
	// -------------------------------------------------------------------------

	/** Transition a ticket's status. */
	@PutMapping("/api/tickets/{id}/status")
	public ResponseEntity<TicketResponse> updateStatus(@PathVariable UUID id,
			@Valid @RequestBody UpdateTicketStatusRequest request) {
		return ResponseEntity.ok(ticketService.updateStatus(id, request.status(), request.changedByUserId()));
	}

	// -------------------------------------------------------------------------
	// Status history
	// -------------------------------------------------------------------------

	/** Retrieve the full status-change history for a ticket. */
	@GetMapping("/api/tickets/{id}/history")
	public ResponseEntity<List<TicketStatusHistoryResponse>> getStatusHistory(@PathVariable UUID id) {
		return ResponseEntity.ok(ticketService.getStatusHistory(id));
	}

	// -------------------------------------------------------------------------
	// Link ticket to commit
	// -------------------------------------------------------------------------

	/**
	 * Links a ticket to a commit. Enforces RCDO defaulting and duplicate-link
	 * prevention.
	 */
	@PutMapping("/api/plans/{planId}/commits/{commitId}/link-ticket")
	public ResponseEntity<LinkTicketResponse> linkTicket(@PathVariable UUID planId, @PathVariable UUID commitId,
			@Valid @RequestBody LinkTicketRequest request) {
		return ResponseEntity.ok(linkTicketService.linkTicket(planId, commitId, request.workItemId()));
	}
}

