/**
 * Expandable tree view of the full RCDO hierarchy.
 * Supports expand/collapse, status filtering, and title search.
 */
import { useState, useCallback } from "react";
import type { RcdoTreeNode, RcdoNodeType, RcdoNodeStatus } from "../../api/rcdoTypes.js";

export type StatusFilter = "all" | "active-only" | "archived-only";

const NODE_TYPE_ICONS: Record<RcdoNodeType, string> = {
  RALLY_CRY: "🎯",
  DEFINING_OBJECTIVE: "📋",
  OUTCOME: "✅",
};

const NODE_TYPE_LABELS: Record<RcdoNodeType, string> = {
  RALLY_CRY: "Rally Cry",
  DEFINING_OBJECTIVE: "Defining Objective",
  OUTCOME: "Outcome",
};

const STATUS_BADGE_COLORS: Record<RcdoNodeStatus, { bg: string; fg: string }> =
  {
    DRAFT: { bg: "#fef3c7", fg: "#92400e" },
    ACTIVE: { bg: "#d1fae5", fg: "#065f46" },
    ARCHIVED: { bg: "#f3f4f6", fg: "#6b7280" },
  };

// ── Helpers ──────────────────────────────────────────────────────────────────

/** Collect all node IDs in a tree. */
function getAllIds(nodes: RcdoTreeNode[]): Set<string> {
  const ids = new Set<string>();
  function collect(node: RcdoTreeNode) {
    ids.add(node.id);
    node.children.forEach(collect);
  }
  nodes.forEach(collect);
  return ids;
}

/**
 * Filter the tree by status and search query.
 * A parent is kept if any of its descendants passes the filter.
 */
function filterTree(
  nodes: RcdoTreeNode[],
  filter: StatusFilter,
  searchLower: string,
): RcdoTreeNode[] {
  function filterNode(node: RcdoTreeNode): RcdoTreeNode | null {
    const filteredChildren = node.children
      .map(filterNode)
      .filter((n): n is RcdoTreeNode => n !== null);

    const passesStatus =
      filter === "all" ||
      (filter === "active-only" && node.status !== "ARCHIVED") ||
      (filter === "archived-only" && node.status === "ARCHIVED");

    const passesSearch =
      !searchLower || node.title.toLowerCase().includes(searchLower);

    if ((passesStatus && passesSearch) || filteredChildren.length > 0) {
      return { ...node, children: filteredChildren };
    }
    return null;
  }
  return nodes.map(filterNode).filter((n): n is RcdoTreeNode => n !== null);
}

// ── StatusBadge ───────────────────────────────────────────────────────────────

function StatusBadge({ status }: { readonly status: RcdoNodeStatus }) {
  const label = status.charAt(0) + status.slice(1).toLowerCase();
  const { bg, fg } = STATUS_BADGE_COLORS[status];
  return (
    <span
      style={{
        display: "inline-block",
        padding: "1px 8px",
        borderRadius: "999px",
        fontSize: "0.7rem",
        fontWeight: 700,
        letterSpacing: "0.02em",
        background: bg,
        color: fg,
        flexShrink: 0,
      }}
      data-testid={`status-badge-${status.toLowerCase()}`}
    >
      {label}
    </span>
  );
}

// ── TreeNodeItem ──────────────────────────────────────────────────────────────

interface TreeNodeItemProps {
  readonly node: RcdoTreeNode;
  readonly depth: number;
  readonly selectedId: string | null;
  readonly expandedIds: Set<string>;
  readonly onSelect: (id: string) => void;
  readonly onToggleExpand: (id: string) => void;
}

function TreeNodeItem({
  node,
  depth,
  selectedId,
  expandedIds,
  onSelect,
  onToggleExpand,
}: TreeNodeItemProps) {
  const isExpanded = expandedIds.has(node.id);
  const isSelected = selectedId === node.id;
  const hasChildren = node.children.length > 0;

  return (
    <li
      role="treeitem"
      aria-expanded={hasChildren ? isExpanded : undefined}
      aria-selected={isSelected}
      style={{ listStyle: "none", margin: 0, padding: 0 }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "0.375rem",
          padding: "0.375rem 0.5rem",
          paddingLeft: `${depth * 1.25 + 0.5}rem`,
          cursor: "pointer",
          borderRadius: "var(--border-radius)",
          backgroundColor: isSelected
            ? "var(--color-primary)"
            : "transparent",
          color: isSelected ? "#fff" : "var(--color-text)",
          userSelect: "none",
        }}
        onClick={() => onSelect(node.id)}
        data-testid={`tree-node-${node.id}`}
      >
        {/* Expand/collapse toggle */}
        <button
          aria-label={
            hasChildren
              ? isExpanded
                ? `Collapse ${node.title}`
                : `Expand ${node.title}`
              : undefined
          }
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) onToggleExpand(node.id);
          }}
          tabIndex={-1}
          style={{
            background: "none",
            border: "none",
            cursor: hasChildren ? "pointer" : "default",
            color: "inherit",
            padding: 0,
            width: "1rem",
            textAlign: "center",
            flexShrink: 0,
            opacity: hasChildren ? 1 : 0,
            fontSize: "0.75rem",
          }}
          aria-hidden={!hasChildren}
        >
          {isExpanded ? "▾" : "▸"}
        </button>

        {/* Node type icon */}
        <span
          aria-label={NODE_TYPE_LABELS[node.nodeType]}
          title={NODE_TYPE_LABELS[node.nodeType]}
          style={{ flexShrink: 0 }}
        >
          {NODE_TYPE_ICONS[node.nodeType]}
        </span>

        {/* Title */}
        <span
          style={{
            flex: 1,
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
          }}
        >
          {node.title}
        </span>

        {/* Status badge */}
        <StatusBadge status={node.status} />
      </div>

      {/* Children */}
      {hasChildren && isExpanded && (
        <ul
          role="group"
          style={{ margin: 0, padding: 0, listStyle: "none" }}
        >
          {node.children.map((child) => (
            <TreeNodeItem
              key={child.id}
              node={child}
              depth={depth + 1}
              selectedId={selectedId}
              expandedIds={expandedIds}
              onSelect={onSelect}
              onToggleExpand={onToggleExpand}
            />
          ))}
        </ul>
      )}
    </li>
  );
}

// ── RcdoTreeView ──────────────────────────────────────────────────────────────

export interface RcdoTreeViewProps {
  readonly nodes: RcdoTreeNode[];
  readonly selectedId: string | null;
  readonly onSelect: (id: string) => void;
  readonly statusFilter: StatusFilter;
  readonly searchQuery: string;
}

export function RcdoTreeView({
  nodes,
  selectedId,
  onSelect,
  statusFilter,
  searchQuery,
}: RcdoTreeViewProps) {
  // Start with top-level Rally Cry nodes expanded
  const [expandedIds, setExpandedIds] = useState<Set<string>>(() => {
    const initial = new Set<string>();
    nodes.forEach((n) => {
      if (n.nodeType === "RALLY_CRY") initial.add(n.id);
    });
    return initial;
  });

  const toggleExpand = useCallback((id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }, []);

  const expandAll = useCallback(() => {
    setExpandedIds(getAllIds(nodes));
  }, [nodes]);

  const collapseAll = useCallback(() => {
    setExpandedIds(new Set());
  }, []);

  const searchLower = searchQuery.trim().toLowerCase();
  const filteredNodes = filterTree(nodes, statusFilter, searchLower);

  // When searching, auto-expand everything so results are visible
  const effectiveExpandedIds = searchLower
    ? getAllIds(nodes)
    : expandedIds;

  const btnStyle: React.CSSProperties = {
    background: "none",
    border: "1px solid var(--color-border)",
    borderRadius: "var(--border-radius)",
    padding: "0.2rem 0.6rem",
    cursor: "pointer",
    fontSize: "0.75rem",
    color: "var(--color-text-muted)",
  };

  return (
    <div
      style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}
      data-testid="rcdo-tree-view"
    >
      {/* Expand / Collapse all controls */}
      <div style={{ display: "flex", gap: "0.5rem" }}>
        <button onClick={expandAll} style={btnStyle} aria-label="Expand all nodes">
          Expand all
        </button>
        <button onClick={collapseAll} style={btnStyle} aria-label="Collapse all nodes">
          Collapse all
        </button>
      </div>

      {/* Tree */}
      <ul
        role="tree"
        aria-label="RCDO hierarchy"
        style={{ margin: 0, padding: 0, listStyle: "none" }}
      >
        {filteredNodes.length === 0 ? (
          <li
            style={{
              padding: "1rem",
              textAlign: "center",
              color: "var(--color-text-muted)",
              fontSize: "0.875rem",
            }}
          >
            No nodes match the current filter.
          </li>
        ) : (
          filteredNodes.map((node) => (
            <TreeNodeItem
              key={node.id}
              node={node}
              depth={0}
              selectedId={selectedId}
              expandedIds={effectiveExpandedIds}
              onSelect={onSelect}
              onToggleExpand={toggleExpand}
            />
          ))
        )}
      </ul>
    </div>
  );
}

/**
 * Create and edit form for RCDO nodes.
 * - Create mode: nodeType and optional defaultParentId are pre-set; parent selector
 *   is shown for DOs (must pick a Rally Cry) and Outcomes (must pick a DO).
 * - Edit mode: title/description/owner fields are pre-filled; parent selector hidden.
 */
import { useState, type FormEvent } from "react";
import type {
  RcdoTreeNode,
  RcdoNodeType,
  RcdoNodeStatus,
  CreateRcdoNodePayload,
  UpdateRcdoNodePayload,
} from "../../api/rcdoTypes.js";

// ── Helpers ──────────────────────────────────────────────────────────────────

/** Flatten tree to find all nodes of a given type (active or draft). */
function flattenByType(
  nodes: RcdoTreeNode[],
  targetType: RcdoNodeType,
): RcdoTreeNode[] {
  const result: RcdoTreeNode[] = [];
  function collect(node: RcdoTreeNode) {
    if (node.nodeType === targetType && node.status !== "ARCHIVED") {
      result.push(node);
    }
    node.children.forEach(collect);
  }
  nodes.forEach(collect);
  return result;
}

/** Returns the parent type required for a given node type, or null for Rally Cries. */
function requiredParentType(nodeType: RcdoNodeType): RcdoNodeType | null {
  switch (nodeType) {
    case "RALLY_CRY":
      return null;
    case "DEFINING_OBJECTIVE":
      return "RALLY_CRY";
    case "OUTCOME":
      return "DEFINING_OBJECTIVE";
  }
}

const NODE_TYPE_LABELS: Record<RcdoNodeType, string> = {
  RALLY_CRY: "Rally Cry",
  DEFINING_OBJECTIVE: "Defining Objective",
  OUTCOME: "Outcome",
};

// ── Form field shape ──────────────────────────────────────────────────────────

interface FormValues {
  title: string;
  description: string;
  ownerTeamId: string;
  ownerUserId: string;
  parentId: string;
  /** Outcome-only field (UI only; not persisted as a separate column). */
  targetMetric: string;
}

type FormErrors = Partial<Record<keyof FormValues, string>>;

// ── Props ─────────────────────────────────────────────────────────────────────

interface CreateModeProps {
  readonly mode: "create";
  readonly nodeType: RcdoNodeType;
  readonly defaultParentId?: string;
  readonly tree: RcdoTreeNode[];
  readonly onSubmit: (payload: CreateRcdoNodePayload) => Promise<void>;
  readonly onCancel: () => void;
}

interface EditModeProps {
  readonly mode: "edit";
  readonly nodeType: RcdoNodeType;
  readonly status: RcdoNodeStatus;
  readonly initialValues: {
    readonly title: string;
    readonly description?: string;
    readonly ownerTeamId?: string;
    readonly ownerUserId?: string;
  };
  readonly tree: RcdoTreeNode[];
  readonly onSubmit: (payload: UpdateRcdoNodePayload) => Promise<void>;
  readonly onCancel: () => void;
}

export type RcdoNodeFormProps = CreateModeProps | EditModeProps;

// ── RcdoNodeForm ──────────────────────────────────────────────────────────────

export function RcdoNodeForm(props: RcdoNodeFormProps) {
  const { nodeType, onCancel } = props;

  const [values, setValues] = useState<FormValues>({
    title: props.mode === "edit" ? props.initialValues.title : "",
    description:
      props.mode === "edit" ? (props.initialValues.description ?? "") : "",
    ownerTeamId:
      props.mode === "edit" ? (props.initialValues.ownerTeamId ?? "") : "",
    ownerUserId:
      props.mode === "edit" ? (props.initialValues.ownerUserId ?? "") : "",
    parentId: props.mode === "create" ? (props.defaultParentId ?? "") : "",
    targetMetric: "",
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const parentType = requiredParentType(nodeType);
  const validParents = parentType ? flattenByType(props.tree, parentType) : [];

  function handleChange(field: keyof FormValues, value: string) {
    setValues((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => ({ ...prev, [field]: undefined }));
    }
  }

  function validate(): boolean {
    const next: FormErrors = {};
    if (!values.title.trim()) {
      next.title = "Title is required";
    }
    if (props.mode === "create" && parentType && !values.parentId) {
      next.parentId = `A ${NODE_TYPE_LABELS[parentType]} parent is required`;
    }
    setErrors(next);
    return Object.keys(next).length === 0;
  }

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!validate()) return;

    setSubmitting(true);
    setSubmitError(null);
    try {
      if (props.mode === "create") {
        const payload: CreateRcdoNodePayload = {
          nodeType,
          title: values.title.trim(),
          ...(values.description.trim()
            ? { description: values.description.trim() }
            : {}),
          ...(values.parentId ? { parentId: values.parentId } : {}),
          ...(values.ownerTeamId.trim()
            ? { ownerTeamId: values.ownerTeamId.trim() }
            : {}),
          ...(values.ownerUserId.trim()
            ? { ownerUserId: values.ownerUserId.trim() }
            : {}),
        };
        await props.onSubmit(payload);
      } else {
        const payload: UpdateRcdoNodePayload = {
          ...(values.title.trim() ? { title: values.title.trim() } : {}),
          ...(values.description.trim()
            ? { description: values.description.trim() }
            : {}),
          ...(values.ownerTeamId.trim()
            ? { ownerTeamId: values.ownerTeamId.trim() }
            : {}),
          ...(values.ownerUserId.trim()
            ? { ownerUserId: values.ownerUserId.trim() }
            : {}),
        };
        await props.onSubmit(payload);
      }
    } catch (err) {
      setSubmitError(
        err instanceof Error ? err.message : "An unexpected error occurred",
      );
    } finally {
      setSubmitting(false);
    }
  }

  const inputStyle: React.CSSProperties = {
    width: "100%",
    padding: "0.5rem",
    border: "1px solid var(--color-border)",
    borderRadius: "var(--border-radius)",
    fontSize: "inherit",
    boxSizing: "border-box",
    fontFamily: "inherit",
  };

  const errorInputStyle: React.CSSProperties = {
    ...inputStyle,
    border: "1px solid var(--color-danger)",
  };

  const fieldStyle: React.CSSProperties = { marginBottom: "1rem" };

  const labelStyle: React.CSSProperties = {
    display: "block",
    marginBottom: "0.25rem",
    fontWeight: 600,
    fontSize: "0.875rem",
  };

  const errorTextStyle: React.CSSProperties = {
    color: "var(--color-danger)",
    fontSize: "0.75rem",
    marginTop: "0.25rem",
    display: "block",
  };

  const headingLabel = `${props.mode === "create" ? "Create" : "Edit"} ${NODE_TYPE_LABELS[nodeType]}`;

  return (
    <form
      onSubmit={handleSubmit}
      noValidate
      aria-label={headingLabel}
      data-testid="rcdo-node-form"
    >
      <h3 style={{ margin: "0 0 1rem", fontSize: "1.125rem" }}>
        {headingLabel}
      </h3>

      {/* Read-only status display in edit mode */}
      {props.mode === "edit" && (
        <div
          style={{
            marginBottom: "1rem",
            fontSize: "0.875rem",
            color: "var(--color-text-muted)",
          }}
        >
          Status:{" "}
          <strong style={{ color: "var(--color-text)" }}>{props.status}</strong>
          <span style={{ marginLeft: "0.5rem", fontSize: "0.75rem" }}>
            (use Activate / Archive actions to change)
          </span>
        </div>
      )}

      {/* Parent selector — create mode only, not for Rally Cries */}
      {props.mode === "create" && parentType && (
        <div style={fieldStyle}>
          <label
            htmlFor="rcdo-form-parent"
            style={labelStyle}
          >
            Parent {NODE_TYPE_LABELS[parentType]}{" "}
            <span aria-hidden="true" style={{ color: "var(--color-danger)" }}>
              *
            </span>
          </label>
          <select
            id="rcdo-form-parent"
            value={values.parentId}
            onChange={(e) => handleChange("parentId", e.target.value)}
            aria-required="true"
            aria-describedby={
              errors.parentId ? "rcdo-form-parent-error" : undefined
            }
            style={errors.parentId ? errorInputStyle : inputStyle}
          >
            <option value="">Select a {NODE_TYPE_LABELS[parentType]}…</option>
            {validParents.map((p) => (
              <option key={p.id} value={p.id}>
                {p.title}
              </option>
            ))}
          </select>
          {errors.parentId && (
            <span id="rcdo-form-parent-error" role="alert" style={errorTextStyle}>
              {errors.parentId}
            </span>
          )}
        </div>
      )}

      {/* Title (required) */}
      <div style={fieldStyle}>
        <label htmlFor="rcdo-form-title" style={labelStyle}>
          Title{" "}
          <span aria-hidden="true" style={{ color: "var(--color-danger)" }}>
            *
          </span>
        </label>
        <input
          id="rcdo-form-title"
          type="text"
          value={values.title}
          onChange={(e) => handleChange("title", e.target.value)}
          aria-required="true"
          aria-describedby={
            errors.title ? "rcdo-form-title-error" : undefined
          }
          style={errors.title ? errorInputStyle : inputStyle}
          placeholder="Enter a clear, concise title"
        />
        {errors.title && (
          <span id="rcdo-form-title-error" role="alert" style={errorTextStyle}>
            {errors.title}
          </span>
        )}
      </div>

      {/* Description */}
      <div style={fieldStyle}>
        <label htmlFor="rcdo-form-description" style={labelStyle}>
          Description
        </label>
        <textarea
          id="rcdo-form-description"
          value={values.description}
          onChange={(e) => handleChange("description", e.target.value)}
          rows={3}
          style={{ ...inputStyle, resize: "vertical" }}
          placeholder="Optional description"
        />
      </div>

      {/* Target Metric — Outcomes only (UI display aid; not a separate backend column) */}
      {nodeType === "OUTCOME" && (
        <div style={fieldStyle}>
          <label htmlFor="rcdo-form-target-metric" style={labelStyle}>
            Target Metric
          </label>
          <input
            id="rcdo-form-target-metric"
            type="text"
            value={values.targetMetric}
            onChange={(e) => handleChange("targetMetric", e.target.value)}
            style={inputStyle}
            placeholder="e.g. Increase NPS from 30 to 50"
          />
          <span
            style={{
              fontSize: "0.75rem",
              color: "var(--color-text-muted)",
              marginTop: "0.25rem",
              display: "block",
            }}
          >
            Displayed as planning context (stored in description when set).
          </span>
        </div>
      )}

      {/* Owner Team ID */}
      <div style={fieldStyle}>
        <label htmlFor="rcdo-form-owner-team" style={labelStyle}>
          Owner Team
        </label>
        <input
          id="rcdo-form-owner-team"
          type="text"
          value={values.ownerTeamId}
          onChange={(e) => handleChange("ownerTeamId", e.target.value)}
          style={inputStyle}
          placeholder="Team ID (optional)"
        />
      </div>

      {/* Owner User ID */}
      <div style={fieldStyle}>
        <label htmlFor="rcdo-form-owner-user" style={labelStyle}>
          Owner User
        </label>
        <input
          id="rcdo-form-owner-user"
          type="text"
          value={values.ownerUserId}
          onChange={(e) => handleChange("ownerUserId", e.target.value)}
          style={inputStyle}
          placeholder="User ID (optional)"
        />
      </div>

      {/* API error */}
      {submitError && (
        <div
          role="alert"
          style={{
            color: "var(--color-danger)",
            marginBottom: "1rem",
            fontSize: "0.875rem",
            padding: "0.5rem",
            background: "#fef2f2",
            borderRadius: "var(--border-radius)",
          }}
        >
          {submitError}
        </div>
      )}

      {/* Action buttons */}
      <div style={{ display: "flex", gap: "0.5rem", justifyContent: "flex-end" }}>
        <button
          type="button"
          onClick={onCancel}
          disabled={submitting}
          style={{
            padding: "0.5rem 1rem",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--border-radius)",
            background: "var(--color-surface)",
            cursor: "pointer",
            fontSize: "inherit",
            fontFamily: "inherit",
          }}
        >
          Cancel
        </button>
        <button
          type="submit"
          disabled={submitting}
          style={{
            padding: "0.5rem 1rem",
            border: "none",
            borderRadius: "var(--border-radius)",
            background: "var(--color-primary)",
            color: "#fff",
            cursor: submitting ? "not-allowed" : "pointer",
            fontSize: "inherit",
            fontFamily: "inherit",
          }}
        >
          {submitting
            ? "Saving…"
            : props.mode === "create"
              ? "Create"
              : "Save changes"}
        </button>
      </div>
    </form>
  );
}

/**
 * Breadcrumb showing the full path from root to the selected RCDO node.
 * Renders: Rally Cry › Defining Objective › Outcome
 */
import type { RcdoTreeNode } from "../../api/rcdoTypes.js";

interface RcdoBreadcrumbProps {
  /** Ordered path from root to (and including) the selected node. */
  readonly path: RcdoTreeNode[];
  /** Called when the user clicks an ancestor node in the breadcrumb. */
  readonly onNavigate?: (id: string) => void;
}

const breadcrumbStyle: React.CSSProperties = {
  display: "flex",
  alignItems: "center",
  flexWrap: "wrap",
  gap: "0.25rem",
  fontSize: "0.875rem",
  color: "var(--color-text-muted)",
  minHeight: "1.5rem",
};

const separatorStyle: React.CSSProperties = {
  margin: "0 0.125rem",
  userSelect: "none",
};

const ancestorButtonStyle: React.CSSProperties = {
  background: "none",
  border: "none",
  color: "var(--color-primary)",
  cursor: "pointer",
  padding: 0,
  fontSize: "inherit",
  textDecoration: "underline",
  textUnderlineOffset: "2px",
};

const currentNodeStyle: React.CSSProperties = {
  color: "var(--color-text)",
  fontWeight: 600,
};

export function RcdoBreadcrumb({ path, onNavigate }: RcdoBreadcrumbProps) {
  if (path.length === 0) {
    return (
      <nav aria-label="RCDO path" style={breadcrumbStyle}>
        <span>RCDO Hierarchy</span>
      </nav>
    );
  }

  return (
    <nav aria-label="RCDO path" style={breadcrumbStyle}>
      <ol
        style={{ listStyle: "none", margin: 0, padding: 0, display: "flex", alignItems: "center", flexWrap: "wrap", gap: "0.25rem" }}
      >
        {path.map((node, index) => {
          const isLast = index === path.length - 1;
          return (
            <li key={node.id} style={{ display: "flex", alignItems: "center", gap: "0.25rem" }}>
              {index > 0 && (
                <span aria-hidden="true" style={separatorStyle}>
                  ›
                </span>
              )}
              {isLast ? (
                <span style={currentNodeStyle} aria-current="page">
                  {node.title}
                </span>
              ) : (
                <button
                  onClick={() => onNavigate?.(node.id)}
                  style={ancestorButtonStyle}
                  aria-label={`Navigate to ${node.title}`}
                >
                  {node.title}
                </button>
              )}
            </li>
          );
        })}
      </ol>
    </nav>
  );
}

/**
 * Modal confirmation dialog for archiving an RCDO node.
 * Shows an impact warning and blocks confirmation if the node has active children.
 */

interface ArchiveConfirmDialogProps {
  /** Display name of the node to be archived. */
  readonly nodeName: string;
  /**
   * True if the node has at least one non-archived child.
   * In this case the Archive button is disabled and a blocking message is shown.
   */
  readonly hasActiveChildren: boolean;
  readonly onConfirm: () => void;
  readonly onCancel: () => void;
  readonly submitting: boolean;
}

const overlayStyle: React.CSSProperties = {
  position: "fixed",
  inset: 0,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  backgroundColor: "rgba(0, 0, 0, 0.5)",
  zIndex: 1000,
};

const panelStyle: React.CSSProperties = {
  background: "var(--color-surface)",
  borderRadius: "var(--border-radius)",
  padding: "1.5rem",
  maxWidth: "480px",
  width: "90vw",
  boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
};

export function ArchiveConfirmDialog({
  nodeName,
  hasActiveChildren,
  onConfirm,
  onCancel,
  submitting,
}: ArchiveConfirmDialogProps) {
  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-labelledby="archive-dialog-title"
      style={overlayStyle}
    >
      <div style={panelStyle}>
        <h3
          id="archive-dialog-title"
          style={{ margin: "0 0 1rem", fontSize: "1.125rem" }}
        >
          Archive "{nodeName}"?
        </h3>

        {hasActiveChildren ? (
          <p
            data-testid="archive-blocked-message"
            style={{
              margin: "0 0 1rem",
              color: "var(--color-danger)",
              fontSize: "0.9rem",
              padding: "0.75rem",
              background: "#fef2f2",
              borderRadius: "var(--border-radius)",
            }}
          >
            <strong>Cannot archive.</strong> This node has active child nodes.
            Archive all children first before archiving this node.
          </p>
        ) : (
          <p
            style={{
              margin: "0 0 1rem",
              color: "var(--color-text-muted)",
              fontSize: "0.9rem",
            }}
          >
            Archiving will hide this node from active planning views. Commits
            already linked to this node will retain their linkage, but the node
            will no longer be selectable for new commits.
          </p>
        )}

        <div
          style={{
            display: "flex",
            gap: "0.5rem",
            justifyContent: "flex-end",
          }}
        >
          <button
            onClick={onCancel}
            disabled={submitting}
            style={{
              padding: "0.5rem 1rem",
              border: "1px solid var(--color-border)",
              borderRadius: "var(--border-radius)",
              background: "var(--color-surface)",
              cursor: "pointer",
              fontSize: "inherit",
              fontFamily: "inherit",
            }}
          >
            Cancel
          </button>
          <button
            onClick={onConfirm}
            disabled={hasActiveChildren || submitting}
            aria-disabled={hasActiveChildren || submitting}
            data-testid="archive-confirm-button"
            style={{
              padding: "0.5rem 1rem",
              border: "none",
              borderRadius: "var(--border-radius)",
              background:
                hasActiveChildren
                  ? "var(--color-border)"
                  : "var(--color-danger)",
              color: hasActiveChildren ? "var(--color-text-muted)" : "#fff",
              cursor:
                hasActiveChildren || submitting ? "not-allowed" : "pointer",
              fontSize: "inherit",
              fontFamily: "inherit",
            }}
          >
            {submitting ? "Archiving…" : "Archive"}
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * Re-parent dialog for moving an RCDO node to a different valid parent.
 * Shows all non-archived parents of the required type.
 */
import { useState } from "react";
import type { RcdoTreeNode, RcdoNodeType } from "../../api/rcdoTypes.js";

// ── Helpers ──────────────────────────────────────────────────────────────────

function flattenByType(
  nodes: RcdoTreeNode[],
  targetType: RcdoNodeType,
  excludeId?: string,
): RcdoTreeNode[] {
  const result: RcdoTreeNode[] = [];
  function collect(node: RcdoTreeNode) {
    if (
      node.nodeType === targetType &&
      node.status !== "ARCHIVED" &&
      node.id !== excludeId
    ) {
      result.push(node);
    }
    node.children.forEach(collect);
  }
  nodes.forEach(collect);
  return result;
}

function requiredParentType(nodeType: RcdoNodeType): RcdoNodeType | null {
  switch (nodeType) {
    case "RALLY_CRY":
      return null;
    case "DEFINING_OBJECTIVE":
      return "RALLY_CRY";
    case "OUTCOME":
      return "DEFINING_OBJECTIVE";
  }
}

const NODE_TYPE_LABELS: Record<RcdoNodeType, string> = {
  RALLY_CRY: "Rally Cry",
  DEFINING_OBJECTIVE: "Defining Objective",
  OUTCOME: "Outcome",
};

// ── MoveNodeDialog ────────────────────────────────────────────────────────────

interface MoveNodeDialogProps {
  readonly nodeName: string;
  readonly nodeType: RcdoNodeType;
  readonly nodeId: string;
  readonly currentParentId?: string;
  readonly tree: RcdoTreeNode[];
  readonly onConfirm: (newParentId: string) => void;
  readonly onCancel: () => void;
  readonly submitting: boolean;
}

const overlayStyle: React.CSSProperties = {
  position: "fixed",
  inset: 0,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  backgroundColor: "rgba(0, 0, 0, 0.5)",
  zIndex: 1000,
};

const panelStyle: React.CSSProperties = {
  background: "var(--color-surface)",
  borderRadius: "var(--border-radius)",
  padding: "1.5rem",
  maxWidth: "480px",
  width: "90vw",
  boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
};

export function MoveNodeDialog({
  nodeName,
  nodeType,
  nodeId,
  currentParentId,
  tree,
  onConfirm,
  onCancel,
  submitting,
}: MoveNodeDialogProps) {
  const [selectedParentId, setSelectedParentId] = useState(
    currentParentId ?? "",
  );

  const parentType = requiredParentType(nodeType);

  // Rally Cries cannot be moved (they are top-level)
  if (!parentType) {
    return (
      <div role="dialog" aria-modal="true" aria-labelledby="move-dialog-title" style={overlayStyle}>
        <div style={panelStyle}>
          <h3 id="move-dialog-title" style={{ margin: "0 0 1rem" }}>
            Cannot Move Rally Cry
          </h3>
          <p style={{ color: "var(--color-text-muted)", marginBottom: "1rem" }}>
            Rally Cry nodes are at the top of the hierarchy and cannot be
            re-parented.
          </p>
          <div style={{ display: "flex", justifyContent: "flex-end" }}>
            <button
              onClick={onCancel}
              style={{
                padding: "0.5rem 1rem",
                border: "1px solid var(--color-border)",
                borderRadius: "var(--border-radius)",
                background: "var(--color-surface)",
                cursor: "pointer",
                fontSize: "inherit",
                fontFamily: "inherit",
              }}
            >
              Close
            </button>
          </div>
        </div>
      </div>
    );
  }

  const validParents = flattenByType(tree, parentType, nodeId);

  return (
    <div role="dialog" aria-modal="true" aria-labelledby="move-dialog-title" style={overlayStyle}>
      <div style={panelStyle}>
        <h3 id="move-dialog-title" style={{ margin: "0 0 1rem", fontSize: "1.125rem" }}>
          Move "{nodeName}"
        </h3>
        <p
          style={{
            margin: "0 0 1rem",
            color: "var(--color-text-muted)",
            fontSize: "0.875rem",
          }}
        >
          Select a new {NODE_TYPE_LABELS[parentType]} parent:
        </p>

        <select
          value={selectedParentId}
          onChange={(e) => setSelectedParentId(e.target.value)}
          aria-label={`Select new ${NODE_TYPE_LABELS[parentType]} parent`}
          style={{
            width: "100%",
            padding: "0.5rem",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--border-radius)",
            fontSize: "inherit",
            fontFamily: "inherit",
            marginBottom: "1rem",
          }}
        >
          <option value="">Choose a {NODE_TYPE_LABELS[parentType]}…</option>
          {validParents.map((parent) => (
            <option key={parent.id} value={parent.id}>
              {parent.title}
            </option>
          ))}
        </select>

        {validParents.length === 0 && (
          <p
            style={{
              fontSize: "0.875rem",
              color: "var(--color-warning)",
              marginBottom: "0.5rem",
            }}
          >
            No valid {NODE_TYPE_LABELS[parentType]} nodes available.
          </p>
        )}

        <div style={{ display: "flex", gap: "0.5rem", justifyContent: "flex-end" }}>
          <button
            onClick={onCancel}
            disabled={submitting}
            style={{
              padding: "0.5rem 1rem",
              border: "1px solid var(--color-border)",
              borderRadius: "var(--border-radius)",
              background: "var(--color-surface)",
              cursor: "pointer",
              fontSize: "inherit",
              fontFamily: "inherit",
            }}
          >
            Cancel
          </button>
          <button
            onClick={() => {
              if (selectedParentId) onConfirm(selectedParentId);
            }}
            disabled={!selectedParentId || submitting}
            aria-disabled={!selectedParentId || submitting}
            style={{
              padding: "0.5rem 1rem",
              border: "none",
              borderRadius: "var(--border-radius)",
              background:
                selectedParentId ? "var(--color-primary)" : "var(--color-border)",
              color: selectedParentId ? "#fff" : "var(--color-text-muted)",
              cursor:
                !selectedParentId || submitting ? "not-allowed" : "pointer",
              fontSize: "inherit",
              fontFamily: "inherit",
            }}
          >
            {submitting ? "Moving…" : "Move here"}
          </button>
        </div>
      </div>
    </div>
  );
}

