              display: "inline-flex",
              alignItems: "center",
              justifyContent: "center",
              width: "1.5rem",
              height: "1.5rem",
              borderRadius: "50%",
              background: "var(--color-primary)",
              color: "#fff",
              fontSize: "0.75rem",
              fontWeight: 700,
              flexShrink: 0,
