          {/* Title */}
          <button
            type="button"
            onClick={() => setExpanded((e) => !e)}
            aria-expanded={expanded}
            data-testid={`commit-title-${commit.id}`}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontWeight: 600,
              fontSize: "0.9rem",
              textAlign: "left",
              padding: 0,
              flex: 1,
              color: "var(--color-text)",
              fontFamily: "inherit",
            }}
          >
            {commit.title}
          </button>

          {/* Metadata badges */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "0.375rem",
              flexShrink: 0,
              flexWrap: "wrap",
