                <button
                  type="button"
                  onClick={() => onMoveDown(commit.id)}
                  disabled={isLast}
                  aria-label={`Move down: ${commit.title}`}
                  data-testid={`move-down-${commit.id}`}
                  style={{
                    background: "none",
