        {/* Inline expanded detail */}
        {expanded && (
          <div
            data-testid={`commit-detail-${commit.id}`}
            style={{
              marginTop: "0.75rem",
              paddingTop: "0.75rem",
              borderTop: "1px solid var(--color-border)",
              display: "flex",
              flexDirection: "column",
              gap: "0.5rem",
              fontSize: "0.875rem",
