function buildRcdoLabels(): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(nodes: typeof rcdoTree) {
    if (!nodes) return;
    for (const n of nodes) {
      map[n.id] = n.title;
      traverse(n.children);
    }
  }
  traverse(rcdoTree ?? []);
  return map;
}

arguments.newText:
function buildRcdoLabels(): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(nodes: typeof rcdoTree, path: string[] = []) {
    if (!nodes) return;
    for (const n of nodes) {
      const nextPath = [...path, n.title];
      map[n.id] = nextPath.join(" > ");
      traverse(n.children, nextPath);
    }
  }
  traverse(rcdoTree ?? []);
  return map;
}

